import React from 'react';
import { CommissionStatus } from '../types';
import { STATUS_STEPS } from '../constants';

interface ProgressBarProps {
  currentStatus: CommissionStatus;
}

export const ProgressBar: React.FC<ProgressBarProps> = ({ currentStatus }) => {
  const currentIndex = STATUS_STEPS.indexOf(currentStatus);
  const totalSteps = STATUS_STEPS.length;
  // Calculate percentage (0 to 100)
  const progress = Math.min(100, Math.max(0, (currentIndex / (totalSteps - 1)) * 100));

  return (
    <div className="w-full">
      <div className="flex justify-between items-center mb-1.5 px-1">
         <span className="text-[10px] font-bold text-stone-400 tracking-wider">PROJECT PROGRESS</span>
         <span className="text-[10px] font-bold text-[#1a472a] bg-[#1a472a]/10 px-2 py-0.5 rounded-full">
            {Math.round(progress)}%
         </span>
      </div>

      {/* Bar container */}
      <div className="h-2.5 bg-stone-200 rounded-full overflow-hidden relative">
        {/* Animated striped background effect (optional aesthetic) */}
        <div className="absolute inset-0 bg-[linear-gradient(45deg,rgba(255,255,255,0.2)_25%,transparent_25%,transparent_50%,rgba(255,255,255,0.2)_50%,rgba(255,255,255,0.2)_75%,transparent_75%,transparent)] bg-[length:1rem_1rem] opacity-30 animate-[spin_3s_linear_infinite]" style={{animationDirection: 'reverse'}}></div>

        {/* Fill */}
        <div 
          className="h-full bg-gradient-to-r from-emerald-400 to-[#1a472a] transition-all duration-700 ease-out rounded-full relative"
          style={{ width: `${progress}%` }}
        >
             {/* Shine effect */}
             <div className="absolute top-0 right-0 bottom-0 width-[2px] bg-white/30 blur-[1px]"></div>
        </div>
      </div>

      {/* Steps labels (Simplified for cleaner look) */}
      <div className="flex justify-between mt-2 px-1">
         {STATUS_STEPS.map((step, index) => {
            const isActive = index <= currentIndex;
            const isCurrent = index === currentIndex;

            // On mobile/small cards, showing all text might be crowded. 
            // We show dots for most, and text for start/end/current.
            const showLabel = index === 0 || index === totalSteps - 1 || isCurrent;

            return (
                <div key={step} className="flex flex-col items-center relative group">
                    {/* Dot indicator */}
                    <div className={`w-1.5 h-1.5 rounded-full mb-1 transition-colors duration-300 ${isActive ? 'bg-[#1a472a]' : 'bg-stone-300'}`}></div>

                    {/* Text Label */}
                    <span className={`text-[9px] font-bold whitespace-nowrap transition-colors duration-300 absolute top-3 ${isCurrent ? 'text-[#1a472a] scale-110' : 'text-stone-300'} ${!showLabel ? 'opacity-0 group-hover:opacity-100' : 'opacity-100'}`}>
                        {step}
                    </span>
                </div>
            )
         })}
      </div>
    </div>
  );
};

