import React, { useState, useEffect, useMemo } from 'react';
import { Commission, CommissionStatus, ThemeMode } from './types';
import { MOCK_COMMISSIONS } from './constants';
import { CommissionCard } from './components/CommissionCard';
import { AddCommissionForm } from './components/AddCommissionForm';
import { EditCommissionForm } from './components/EditCommissionForm';
import { Search, Sparkles, Lock, Unlock, ArrowRight, ChevronDown, Palette } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [commissions, setCommissions] = useState<Commission[]>([]);
  const [viewMode, setViewMode] = useState<ThemeMode>('client'); // Default is client
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<CommissionStatus | 'All'>('All');
  const [isAdding, setIsAdding] = useState(false);
  const [editingCommission, setEditingCommission] = useState<Commission | null>(null);
  const [selectedArtistFilter, setSelectedArtistFilter] = useState<string>('All'); // New: For Header Dropdown

  // Artist Login State
  const [currentArtist, setCurrentArtist] = useState<string>('');
  const [loginInput, setLoginInput] = useState('');

  // Data Loading State
  const [isLoaded, setIsLoaded] = useState(false);

  // Initialize Data
  useEffect(() => {
    const stored = localStorage.getItem('arttrack_commissions_zh_v1');
    if (stored) {
      try {
        let parsed = JSON.parse(stored);
        if (Array.isArray(parsed)) {
             // Migration: Ensure artistId exists
            parsed = parsed.map((c: any) => ({
                ...c,
                artistId: c.artistId || 'Unknown'
            }));
            setCommissions(parsed);
        } else {
            setCommissions(MOCK_COMMISSIONS);
        }
      } catch (e) {
        console.error("Failed to parse commissions from local storage", e);
        setCommissions(MOCK_COMMISSIONS);
      }
    } else {
      setCommissions(MOCK_COMMISSIONS);
    }
    setIsLoaded(true);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Persistence
  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem('arttrack_commissions_zh_v1', JSON.stringify(commissions));
    }
  }, [commissions, isLoaded]);

  // Extract Unique Artists for Dropdown
  const uniqueArtists = useMemo(() => {
    const artists = new Set(commissions.map(c => c.artistId).filter(Boolean));
    return Array.from(artists);
  }, [commissions]);

  // Handlers
  const handleUpdateStatus = (id: string, newStatus: CommissionStatus) => {
    setCommissions(prev => prev.map(c => 
      c.id === id ? { ...c, status: newStatus, lastUpdated: new Date().toISOString().split('T')[0] } : c
    ));
  };

  const handleDelete = (id: string) => {
    // Confirmation is now handled in the CommissionCard component
    setCommissions(prev => prev.filter(c => c.id !== id));
  };

  const handleAdd = (newCommission: Commission) => {
    // Overwrite artistId with currently logged in artist
    const commissionToAdd = {
        ...newCommission,
        artistId: currentArtist || 'Unknown'
    };
    setCommissions(prev => [commissionToAdd, ...prev]);
    setIsAdding(false);
  };

  const handleEdit = (updatedCommission: Commission) => {
    setCommissions(prev => prev.map(c => 
        c.id === updatedCommission.id ? updatedCommission : c
    ));
    setEditingCommission(null);
  };

  const toggleViewMode = () => {
    setViewMode(prev => prev === 'client' ? 'admin' : 'client');
    // Reset filters when switching views
    if (viewMode === 'client') {
        setSelectedArtistFilter('All');
    }
  };

  const handleLogin = (e: React.FormEvent) => {
      e.preventDefault();
      if (loginInput.trim()) {
          setCurrentArtist(loginInput.trim());
          setLoginInput('');
      }
  };

  const handleLogout = () => {
      setCurrentArtist('');
  };

  // Filter Logic
  const filteredCommissions = useMemo(() => {
    return commissions.filter(c => {
      // 1. Admin Mode: Must match logged in artist
      if (viewMode === 'admin' && currentArtist) {
          if (c.artistId !== currentArtist) return false;
      }

      // 2. Client Mode: Filter by Selected Artist Dropdown
      if (viewMode === 'client' && selectedArtistFilter !== 'All') {
          if (c.artistId !== selectedArtistFilter) return false;
      }

      // 3. Search & Filter
      const term = searchTerm.toLowerCase();
      const matchesSearch = 
        c.clientName.toLowerCase().includes(term) || 
        c.title.toLowerCase().includes(term) ||
        c.id.toLowerCase().includes(term);
        // Removed artistId search here because it's handled by the dropdown now

      const matchesFilter = statusFilter === 'All' || c.status === statusFilter;

      return matchesSearch && matchesFilter;
    });
  }, [commissions, searchTerm, statusFilter, viewMode, currentArtist, selectedArtistFilter]);

  // View Logic: Should we show the list?
  const shouldShowList = useMemo(() => {
    // Admin: Show list only if logged in
    if (viewMode === 'admin' && currentArtist) {
          return !!currentArtist;
    }
    // Client: Must search to see results
    return searchTerm.trim().length > 0;
  }, [viewMode, searchTerm, currentArtist]);

  // Statistics
  const stats = useMemo(() => {
    let targetCommissions = commissions;

    if (viewMode === 'admin') {
        // Admin: Filter by current artist
        targetCommissions = currentArtist 
            ? commissions.filter(c => c.artistId === currentArtist)
            : [];
    } else {
        // Client: Filter by Dropdown Selection ONLY
        // This ensures stats reflect the "Teacher's workload", not just the search result
        if (selectedArtistFilter !== 'All') {
            targetCommissions = commissions.filter(c => c.artistId === selectedArtistFilter);
        }
    }

    return {
        queue: targetCommissions.filter(c => c.status === CommissionStatus.QUEUE).length,
        active: targetCommissions.filter(c => c.status !== CommissionStatus.QUEUE && c.status !== CommissionStatus.DONE).length,
        done: targetCommissions.filter(c => c.status === CommissionStatus.DONE).length
    }
  }, [commissions, viewMode, currentArtist, selectedArtistFilter]);

  return (
    <div className="min-h-screen bg-[#fffafb] text-stone-700 selection:bg-pink-200 flex flex-col">

      {/* Main Content */}
      <main className="flex-grow pt-12 pb-10 px-6 max-w-5xl mx-auto w-full">

        {/* Top Header with Artist Selection */}
        <div className="flex items-center justify-between mb-8 text-[#ff5c8d] opacity-90">
            <div className="flex items-center gap-2">
                <div className="bg-[#ffa9c2] text-white p-1.5 rounded-lg shadow-sm transform -rotate-3">
                    <Sparkles size={18} />
                </div>

                {viewMode === 'client' ? (
                     <div className="relative group">
                        <select 
                            value={selectedArtistFilter}
                            onChange={(e) => setSelectedArtistFilter(e.target.value)}
                            className="appearance-none bg-transparent text-xl font-bold tracking-wide border-b-2 border-transparent hover:border-[#ffa9c2]/20 cursor-pointer pr-8 focus:outline-none transition-all text-[#ff5c8d] py-1"
                        >
                            <option value="All">所有繪師</option>
                            {uniqueArtists.map(artist => (
                                <option key={artist} value={artist}>{artist} 的委託表</option>
                            ))}
                        </select>
                        <div className="absolute right-0 top-1/2 -translate-y-1/2 pointer-events-none text-[#ffa9c2]/50 group-hover:translate-y-0 transition-transform">
                            <ChevronDown size={20} />
                        </div>
                     </div>
                ) : (
                    <h1 className="text-xl font-bold tracking-wide">Commission Tracker</h1>
                )}
            </div>

            {/* Show Logged in Artist in Admin Mode */}
            {viewMode === 'admin' && currentArtist && (
                <div className="flex items-center gap-3">
                    <span className="text-sm font-bold bg-white px-3 py-1.5 rounded-full border border-stone-200 shadow-sm text-stone-600">
                        👨‍🎨 {currentArtist}
                    </span>
                    <button 
                        onClick={handleLogout}
                        className="text-xs font-bold text-stone-400 hover:text-stone-600 underline"
                    >
                        登出
                    </button>
                </div>
            )}
        </div>

        {/* Intro / Stats */}
        {/* If Admin + Not Logged In, hide stats to keep login screen clean */}
        {!(viewMode === 'admin' && !currentArtist) && (
            <div className="mb-10 text-center sm:text-left sm:flex justify-between items-end animate-in fade-in slide-in-from-top-4 duration-500">
                <div className="mb-8 sm:mb-0">
                    <h2 className="text-3xl font-bold text-[#ff5c8d] mb-3 tracking-tight">
                        {viewMode === 'client' 
                            ? (selectedArtistFilter === 'All' ? '委託進度一覽 ✨' : `${selectedArtistFilter} 的委託現況 🎨`)
                            : `歡迎回來，${currentArtist}！🎨`
                        }
                    </h2>
                    <p className="text-stone-500 max-w-lg font-medium leading-relaxed">
                        {viewMode === 'client' 
                            ? '選擇繪師並輸入您的 ID 或暱稱，即可查詢進度～' 
                            : '今天也要元氣滿滿的畫圖！這裡可以管理排單和進度喔。'}
                    </p>
                </div>
                <div className="flex gap-3 justify-center sm:justify-end text-sm">
                    <div className="bg-white border-2 border-stone-200 px-4 py-3 rounded-2xl text-center min-w-[80px] shadow-sm transform hover:-translate-y-1 transition-transform">
                        <div className="text-2xl font-bold text-stone-600">{stats.queue}</div>
                        <div className="text-xs text-stone-400 font-bold">排單中</div>
                    </div>
                    <div className="bg-white border-2 border-pink-100 px-4 py-3 rounded-2xl text-center min-w-[80px] shadow-sm transform hover:-translate-y-1 transition-transform">
                        <div className="text-2xl font-bold text-[#ff5c8d]">{stats.active}</div>
                        <div className="text-xs text-pink-400 font-bold">繪製中</div>
                    </div>
                    <div className="bg-white border-2 border-[#ffa9c2]/20 px-4 py-3 rounded-2xl text-center min-w-[80px] shadow-sm transform hover:-translate-y-1 transition-transform">
                        <div className="text-2xl font-bold text-[#ffa9c2]">{stats.done}</div>
                        <div className="text-xs text-[#ffa9c2]/70 font-bold">已完成</div>
                    </div>
                </div>
            </div>
        )}

        {/* --- Logic Branching --- */}

        {viewMode === 'admin' && !currentArtist ? (
            // === Admin Login Screen ===
            <div className="flex flex-col items-center justify-center py-20 animate-in zoom-in-95 duration-300">
                <div className="bg-white p-8 rounded-3xl shadow-xl shadow-pink-100 border-2 border-pink-50 max-w-md w-full text-center">
                    <div className="w-16 h-16 bg-pink-100 text-[#ff5c8d] rounded-2xl flex items-center justify-center mx-auto mb-6 transform rotate-3">
                        <Palette size={32} />
                    </div>
                    <h3 className="text-2xl font-bold text-stone-700 mb-2">繪師後台登入</h3>
                    <p className="text-stone-400 mb-8 font-medium">請輸入您的名稱以管理委託</p>

                    <form onSubmit={handleLogin} className="space-y-4">
                        <input 
                            type="text" 
                            placeholder="輸入名稱 (例如: 兔兔老師)" 
                            className="w-full bg-stone-50 border-2 border-stone-200 rounded-xl px-4 py-3 text-center font-bold text-stone-700 focus:outline-none focus:border-[#ffa9c2] focus:ring-4 focus:ring-[#ffa9c2]/20 transition-all placeholder:font-normal"
                            value={loginInput}
                            onChange={(e) => setLoginInput(e.target.value)}
                            autoFocus
                        />
                        <button 
                            type="submit"
                            disabled={!loginInput.trim()}
                            className="w-full bg-[#ffa9c2] hover:bg-[#ff94b3] text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-pink-200 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                        >
                            進入管理介面 <ArrowRight size={18} />
                        </button>
                    </form>

                    <div className="mt-6 text-xs text-stone-400">
                        * 此為範例，不需要密碼即可登入
                    </div>
                </div>
            </div>
        ) : (
            // === Main Dashboard (Client Search or Admin Manager) ===
            <>
                {/* Controls - Floating & Rounded */}
                <div className="flex flex-col md:flex-row gap-4 mb-10 sticky top-6 z-40 bg-[#fffafb]/90 p-4 -mx-4 md:mx-0 rounded-3xl border-2 border-white shadow-lg shadow-pink-100/50 backdrop-blur-md animate-in fade-in slide-in-from-bottom-4">
                  <div className="relative flex-grow">
                    <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-stone-400" size={20} />
                    <input 
                      type="text" 
                      placeholder={viewMode === 'client' ? "輸入您的名稱 (ID) 查詢進度..." : "在您的委託中搜尋..."}
                      className="w-full bg-white border-2 border-stone-200 text-stone-700 pl-12 pr-6 py-3 rounded-full focus:ring-4 focus:ring-[#ffa9c2]/10 focus:border-[#ffa9c2] focus:outline-none transition-all placeholder:text-stone-400 font-medium"
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>

                  <div className="flex gap-3 overflow-x-auto pb-2 md:pb-0 hide-scrollbar px-1">
                    <select 
                        className="bg-white border-2 border-stone-200 text-stone-600 px-6 py-3 rounded-full focus:ring-4 focus:ring-[#ffa9c2]/10 focus:border-[#ffa9c2] focus:outline-none font-bold cursor-pointer hover:border-stone-300"
                        value={statusFilter}
                        onChange={(e) => setStatusFilter(e.target.value as any)}
                    >
                        <option value="All">所有狀態</option>
                        {Object.values(CommissionStatus).map(s => (
                            <option key={s} value={s}>{s}</option>
                        ))}
                    </select>

                    {viewMode === 'admin' && (
                        <button 
                            onClick={() => setIsAdding(!isAdding)}
                            className="flex items-center gap-2 bg-[#ffa9c2] hover:bg-[#ff94b3] text-white px-6 py-3 rounded-full font-bold transition-all shadow-lg shadow-pink-200 hover:shadow-xl hover:-translate-y-0.5 whitespace-nowrap active:scale-95"
                        >
                            <Palette size={20} /> 新增委託
                        </button>
                    )}
                  </div>
                </div>

                {/* Add Form */}
                {viewMode === 'admin' && isAdding && (
                    <AddCommissionForm onAdd={handleAdd} onCancel={() => setIsAdding(false)} />
                )}

                {/* List */}
                <div className="space-y-6">
                    {!shouldShowList ? (
                        // Client Mode: No Search Yet
                        <div className="text-center py-20 opacity-70">
                            <div className="mx-auto w-20 h-20 bg-pink-50 rounded-full flex items-center justify-center mb-5 animate-[pulse_3s_ease-in-out_infinite]">
                                <Search className="text-pink-200" size={36} />
                            </div>
                            <h3 className="text-xl font-bold text-stone-500">輸入委託人名稱開始查詢</h3>
                            <p className="text-stone-400 mt-2 font-medium text-sm">請在上方搜尋欄輸入您的 ID 以查看進度</p>
                        </div>
                    ) : filteredCommissions.length === 0 ? (
                        // Search resulted in empty
                        <div className="text-center py-24 bg-white rounded-3xl border-2 border-dashed border-stone-200">
                            <div className="mx-auto w-20 h-20 bg-stone-100 rounded-full flex items-center justify-center mb-4">
                                <Search className="text-stone-400" size={32} />
                            </div>
                            <h3 className="text-xl font-bold text-stone-600">找不到相關委託捏...</h3>
                            <p className="text-stone-400 mt-2 font-medium">
                                {viewMode === 'admin' ? "目前沒有符合條件的委託" : "試試看別的關鍵字？"}
                            </p>
                        </div>
                    ) : (
                        // Results List
                        filteredCommissions.map(commission => (
                            <CommissionCard 
                                key={commission.id}
                                commission={commission}
                                isAdmin={viewMode === 'admin'}
                                onUpdateStatus={handleUpdateStatus}
                                onDelete={handleDelete}
                                onEdit={(c) => setEditingCommission(c)}
                            />
                        ))
                    )}
                </div>
            </>
        )}

      </main>

      {/* Edit Overlay */}
      {editingCommission && (
          <EditCommissionForm 
            commission={editingCommission} 
            onSave={handleEdit} 
            onCancel={() => setEditingCommission(null)} 
          />
      )}

      {/* Footer with Admin Switch */}
      <footer className="py-8 border-t border-stone-200 text-center relative">
        <p className="text-stone-400 text-sm font-medium mb-4">
            © {new Date().getFullYear()} ArtTrack Dashboard. Made with 🩷 for Artists.
        </p>

        <div className="flex justify-center">
            <button 
                onClick={toggleViewMode}
                className={`p-2 rounded-full transition-all duration-300 ${viewMode === 'admin' ? 'bg-stone-200 text-stone-600' : 'text-stone-300 hover:text-stone-400'}`}
                title={viewMode === 'client' ? "繪師登入" : "返回查詢"}
            >
                {viewMode === 'admin' ? <Unlock size={16} /> : <Lock size={16} />}
            </button>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Commission, CommissionStatus } from '../types';
import { Plus, X, Link as LinkIcon, Upload, Image as ImageIcon, Trash2 } from 'lucide-react';

interface AddCommissionFormProps {
  onAdd: (c: Commission) => void;
  onCancel: () => void;
}

export const AddCommissionForm: React.FC<AddCommissionFormProps> = ({ onAdd, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Commission>>({
    clientName: '',
    title: '',
    description: '',
    type: '半身',
    price: 0,
    status: CommissionStatus.QUEUE,
    thumbnailUrl: ''
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        // Limit file size to 800KB to avoid localStorage quota issues
        if (file.size > 800 * 1024) {
            alert("圖片檔案過大 (超過 800KB)，可能導致儲存失敗。\n建議壓縮圖片或使用外部連結。");
            return;
        }

        const reader = new FileReader();
        reader.onloadend = () => {
            setFormData(prev => ({ ...prev, thumbnailUrl: reader.result as string }));
        };
        reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newCommission: Commission = {
      id: `c-${Date.now()}`,
      artistId: '', // Will be filled by parent
      clientName: formData.clientName || '匿名委託人',
      title: formData.title || '未命名委託',
      description: formData.description || '',
      type: formData.type as any,
      price: Number(formData.price),
      status: formData.status as CommissionStatus,
      dateAdded: new Date().toISOString().split('T')[0],
      lastUpdated: new Date().toISOString().split('T')[0],
      thumbnailUrl: formData.thumbnailUrl || ''
    };
    onAdd(newCommission);
  };

  return (
    <div className="bg-white border-2 border-pink-100 rounded-3xl p-8 mb-10 animate-in fade-in zoom-in-95 duration-200 shadow-xl shadow-pink-50/50">
      <div className="flex justify-between items-center mb-8 pb-4 border-b-2 border-stone-100">
        <h3 className="text-xl font-bold text-[#ff5c8d] flex items-center gap-3">
            <div className="bg-pink-100 p-2 rounded-xl text-[#ff5c8d]">
                <Plus size={24} /> 
            </div>
            新增委託單
        </h3>
        <button onClick={onCancel} className="bg-stone-100 p-2 rounded-full text-stone-400 hover:text-stone-600 hover:bg-stone-200 transition-colors">
            <X size={20} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-5">
          <div>
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">委託人名稱 (ID)</label>
            <input 
              required
              type="text" 
              className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium transition-all"
              value={formData.clientName}
              onChange={e => setFormData({...formData, clientName: e.target.value})}
              placeholder="例如: ArtLover99"
            />
          </div>
          <div>
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">委託項目標題</label>
            <input 
              required
              type="text" 
              className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium transition-all"
              value={formData.title}
              onChange={e => setFormData({...formData, title: e.target.value})}
              placeholder="例如: 原創角色立繪"
            />
          </div>
           <div>
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">委託類型</label>
            <div className="relative">
                <select 
                className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium appearance-none cursor-pointer transition-all"
                value={formData.type}
                onChange={e => setFormData({...formData, type: e.target.value as any})}
                >
                    <option value="大頭貼">大頭貼</option>
                    <option value="Q版">Q版</option>
                    <option value="半身">半身</option>
                    <option value="全身">全身</option>
                    <option value="插畫">插畫</option>
                    <option value="立繪設計">立繪設計</option>
                    <option value="社團特殊委託">社團特殊委託</option>
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-stone-400">
                    ▼
                </div>
            </div>
          </div>
        </div>

        <div className="space-y-5">
          <div>
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">價格 (NTD/USD)</label>
            <input 
              type="number" 
              className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium transition-all"
              value={formData.price}
              onChange={e => setFormData({...formData, price: Number(e.target.value)})}
            />
          </div>
           <div>
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">初始狀態</label>
            <div className="relative">
                <select 
                className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium appearance-none cursor-pointer transition-all"
                value={formData.status}
                onChange={e => setFormData({...formData, status: e.target.value as any})}
                >
                {Object.values(CommissionStatus).map(s => (
                    <option key={s} value={s}>{s}</option>
                ))}
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-stone-400">
                    ▼
                </div>
            </div>
          </div>

          {/* Image Upload Section */}
          <div>
             <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">參考圖/縮圖 (上傳或連結)</label>

             {formData.thumbnailUrl ? (
                 <div className="relative group w-full h-32 rounded-2xl overflow-hidden border-2 border-pink-100 bg-pink-50">
                    <img src={formData.thumbnailUrl} alt="Preview" className="w-full h-full object-cover" />
                    <button 
                        type="button"
                        onClick={() => setFormData({...formData, thumbnailUrl: ''})}
                        className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-md"
                    >
                        <Trash2 size={16} />
                    </button>
                 </div>
             ) : (
                <div className="space-y-2">
                    {/* Upload Box */}
                    <div 
                        onClick={() => fileInputRef.current?.click()}
                        className="w-full h-20 border-2 border-dashed border-pink-200 rounded-2xl flex flex-col items-center justify-center text-pink-300 hover:text-pink-400 hover:border-pink-300 hover:bg-pink-50 transition-all cursor-pointer gap-1"
                    >
                        <Upload size={20} />
                        <span className="text-xs font-bold">點擊上傳圖片 (Max 800KB)</span>
                        <input 
                            ref={fileInputRef}
                            type="file" 
                            accept="image/*" 
                            className="hidden" 
                            onChange={handleFileChange}
                        />
                    </div>

                    {/* URL Input Fallback */}
                    <div className="relative">
                        <input 
                            type="url" 
                            className="w-full bg-stone-50 border-2 border-stone-200 rounded-xl pl-9 pr-4 py-2 text-xs text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium transition-all placeholder:text-stone-400"
                            value={formData.thumbnailUrl}
                            onChange={e => setFormData({...formData, thumbnailUrl: e.target.value})}
                            placeholder="或是貼上圖片連結..."
                        />
                        <LinkIcon size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
                    </div>
                </div>
             )}
          </div>
        </div>

        <div className="md:col-span-2">
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">詳細需求描述</label>
            <textarea 
              className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none h-28 resize-none font-medium transition-all"
              value={formData.description}
              onChange={e => setFormData({...formData, description: e.target.value})}
              placeholder="請輸入委託的詳細內容..."
            />
        </div>

        <div className="md:col-span-2 pt-4 flex justify-end border-t border-stone-100 mt-2">
            <button 
                type="submit"
                className="bg-[#ffa9c2] hover:bg-[#ff94b3] text-white font-bold py-3 px-8 rounded-full transition-all shadow-lg shadow-pink-200 hover:-translate-y-0.5 active:scale-95 text-sm"
            >
                建立委託單
            </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Commission, CommissionStatus } from '../types';
import { Save, X, Link as LinkIcon, Upload, Trash2 } from 'lucide-react';

interface EditCommissionFormProps {
  commission: Commission;
  onSave: (updated: Commission) => void;
  onCancel: () => void;
}

export const EditCommissionForm: React.FC<EditCommissionFormProps> = ({ commission, onSave, onCancel }) => {
  const [formData, setFormData] = useState<Commission>(commission);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setFormData(commission);
  }, [commission]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        if (file.size > 800 * 1024) {
            alert("圖片檔案過大 (超過 800KB)，可能導致儲存失敗。\n建議壓縮圖片或使用外部連結。");
            return;
        }

        const reader = new FileReader();
        reader.onloadend = () => {
            setFormData(prev => ({ ...prev, thumbnailUrl: reader.result as string }));
        };
        reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
        ...formData,
        lastUpdated: new Date().toISOString().split('T')[0]
    });
  };

  return (
    <div className="fixed inset-0 bg-stone-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-in fade-in duration-200">
      <div className="bg-white border-2 border-stone-100 rounded-3xl w-full max-w-2xl max-h-[90vh] overflow-y-auto shadow-2xl animate-in zoom-in-95 duration-200">

        <div className="sticky top-0 bg-white/95 backdrop-blur-md px-8 py-5 border-b-2 border-stone-100 flex justify-between items-center z-10">
          <h3 className="text-xl font-bold text-stone-700 flex items-center gap-2">
             編輯委託單
             <span className="text-sm font-medium text-stone-400 bg-stone-100 px-2 py-0.5 rounded-md">#{commission.id}</span>
          </h3>
          <button onClick={onCancel} className="bg-stone-100 p-2 rounded-full text-stone-400 hover:text-stone-600 hover:bg-stone-200 transition-colors">
              <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-5">
            <div>
              <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">委託人名稱 (ID)</label>
              <input 
                required
                type="text" 
                className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium transition-all"
                value={formData.clientName}
                onChange={e => setFormData({...formData, clientName: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">委託項目標題</label>
              <input 
                required
                type="text" 
                className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium transition-all"
                value={formData.title}
                onChange={e => setFormData({...formData, title: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">委託類型</label>
              <div className="relative">
                  <select 
                  className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium appearance-none cursor-pointer transition-all"
                  value={formData.type}
                  onChange={e => setFormData({...formData, type: e.target.value as any})}
                  >
                      <option value="大頭貼">大頭貼</option>
                      <option value="Q版">Q版</option>
                      <option value="半身">半身</option>
                      <option value="全身">全身</option>
                      <option value="插畫">插畫</option>
                      <option value="立繪設計">立繪設計</option>
                      <option value="社團特殊委託">社團特殊委託</option>
                  </select>
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-stone-400">
                      ▼
                  </div>
              </div>
            </div>
          </div>

          <div className="space-y-5">
            <div>
              <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">價格 (NTD/USD)</label>
              <input 
                type="number" 
                className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium transition-all"
                value={formData.price}
                onChange={e => setFormData({...formData, price: Number(e.target.value)})}
              />
            </div>

            {/* Image Upload Section */}
            <div>
               <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">參考圖/縮圖</label>

               {formData.thumbnailUrl ? (
                 <div className="relative group w-full h-32 rounded-2xl overflow-hidden border-2 border-pink-100 bg-pink-50">
                    <img src={formData.thumbnailUrl} alt="Preview" className="w-full h-full object-cover" />
                    <button 
                        type="button"
                        onClick={() => setFormData({...formData, thumbnailUrl: ''})}
                        className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-md"
                    >
                        <Trash2 size={16} />
                    </button>
                 </div>
               ) : (
                <div className="space-y-2">
                    {/* Upload Box */}
                    <div 
                        onClick={() => fileInputRef.current?.click()}
                        className="w-full h-20 border-2 border-dashed border-pink-200 rounded-2xl flex flex-col items-center justify-center text-pink-300 hover:text-pink-400 hover:border-pink-300 hover:bg-pink-50 transition-all cursor-pointer gap-1"
                    >
                        <Upload size={20} />
                        <span className="text-xs font-bold">上傳圖片 (Max 800KB)</span>
                        <input 
                            ref={fileInputRef}
                            type="file" 
                            accept="image/*" 
                            className="hidden" 
                            onChange={handleFileChange}
                        />
                    </div>

                    {/* URL Input Fallback */}
                    <div className="relative">
                        <input 
                            type="url" 
                            className="w-full bg-stone-50 border-2 border-stone-200 rounded-xl pl-9 pr-4 py-2 text-xs text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium transition-all placeholder:text-stone-400"
                            value={formData.thumbnailUrl || ''}
                            onChange={e => setFormData({...formData, thumbnailUrl: e.target.value})}
                            placeholder="或是貼上圖片連結..."
                        />
                        <LinkIcon size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
                    </div>
                </div>
               )}
            </div>

            <div>
               <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">當前狀態</label>
               <div className="relative">
                  <select 
                  className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium appearance-none cursor-pointer transition-all"
                  value={formData.status}
                  onChange={e => setFormData({...formData, status: e.target.value as any})}
                  >
                  {Object.values(CommissionStatus).map(s => (
                      <option key={s} value={s}>{s}</option>
                  ))}
                  </select>
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-stone-400">
                      ▼
                  </div>
              </div>
            </div>
          </div>

          <div className="md:col-span-2">
              <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">詳細需求描述</label>
              <textarea 
                className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none h-32 resize-none font-medium transition-all"
                value={formData.description}
                onChange={e => setFormData({...formData, description: e.target.value})}
              />
          </div>

          <div className="md:col-span-2 pt-6 flex justify-end gap-3 border-t border-stone-100">
               <button 
                  type="button"
                  onClick={onCancel}
                  className="px-6 py-2.5 rounded-full text-stone-500 font-bold hover:bg-stone-100 transition-all text-sm"
              >
                  取消
              </button>
              <button 
                  type="submit"
                  className="bg-[#ffa9c2] hover:bg-[#ff94b3] text-white font-bold py-2.5 px-8 rounded-full transition-all shadow-lg shadow-pink-200 hover:-translate-y-0.5 active:scale-95 text-sm flex items-center gap-2"
              >
                  <Save size={16} /> 儲存變更
              </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Commission, CommissionStatus } from '../types';
import { ProgressBar } from './ProgressBar';
import { STATUS_STEPS } from '../constants';
import { AdminTools } from './AdminTools';
import { 
  Trash2, 
  ChevronRight, 
  ChevronLeft, 
  Calendar, 
  DollarSign, 
  Sparkles,
  Pencil,
  Image as ImageIcon
} from 'lucide-react';

interface CommissionCardProps {
  commission: Commission;
  isAdmin: boolean;
  onUpdateStatus: (id: string, newStatus: CommissionStatus) => void;
  onDelete: (id: string) => void;
  onEdit: (commission: Commission) => void;
}

export const CommissionCard: React.FC<CommissionCardProps> = ({ 
  commission, 
  isAdmin, 
  onUpdateStatus,
  onDelete,
  onEdit
}) => {
  const [showAdminTools, setShowAdminTools] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);

  // Updated Status Colors for Cute Theme (Pill badges)
  const getStatusColor = (status: CommissionStatus) => {
    switch(status) {
      case CommissionStatus.QUEUE: return 'bg-stone-100 text-stone-600 border-stone-200';
      case CommissionStatus.SKETCH: return 'bg-pink-50 text-pink-500 border-pink-200';
      case CommissionStatus.LINEART: return 'bg-rose-50 text-rose-500 border-rose-200';
      case CommissionStatus.COLOR: return 'bg-purple-50 text-purple-500 border-purple-200';
      case CommissionStatus.RENDER: return 'bg-fuchsia-50 text-fuchsia-500 border-fuchsia-200';
      case CommissionStatus.DONE: return 'bg-[#ffa9c2] text-white border-[#ffa9c2]';
      default: return 'bg-stone-100 text-stone-600 border-stone-200';
    }
  };

  const handleNextStep = () => {
    const currentIndex = STATUS_STEPS.indexOf(commission.status);
    if (currentIndex < STATUS_STEPS.length - 1) {
      onUpdateStatus(commission.id, STATUS_STEPS[currentIndex + 1]);
    }
  };

  const handlePrevStep = () => {
    const currentIndex = STATUS_STEPS.indexOf(commission.status);
    if (currentIndex > 0) {
      onUpdateStatus(commission.id, STATUS_STEPS[currentIndex - 1]);
    }
  };

  const handleDeleteClick = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (isDeleting) {
          onDelete(commission.id);
      } else {
          setIsDeleting(true);
          // Optional: Auto reset after 3 seconds if not confirmed
          setTimeout(() => setIsDeleting(false), 3000);
      }
  };

  return (
    <div className="bg-white border-2 border-stone-100 rounded-3xl p-7 shadow-[0_8px_30px_rgb(0,0,0,0.04)] hover:shadow-[0_8px_30px_rgb(0,0,0,0.08)] transition-all duration-300 group hover:-translate-y-1 flex flex-col md:flex-row gap-6">

      {/* Image Section */}
      <div className="flex-shrink-0">
         <div className="w-full md:w-48 h-48 rounded-2xl overflow-hidden border-2 border-stone-100 bg-stone-50 relative group/image">
            {commission.thumbnailUrl ? (
                <img 
                  src={commission.thumbnailUrl} 
                  alt={commission.title} 
                  className="w-full h-full object-cover transition-transform duration-500 group-hover/image:scale-110"
                />
            ) : (
                <div className="w-full h-full flex items-center justify-center text-stone-300">
                    <ImageIcon size={32} />
                </div>
            )}
            {/* Status Overlay on Image for Mobile mainly, but nice everywhere */}
            <div className="absolute top-2 left-2">
                 <span className={`px-2 py-1 rounded-lg text-[10px] font-bold border shadow-sm ${getStatusColor(commission.status)}`}>
                    {commission.status}
                  </span>
            </div>
         </div>
      </div>

      {/* Content Section */}
      <div className="flex-grow flex flex-col justify-between">
        <div>
          <div className="flex justify-between items-start mb-2">
            <div>
              <div className="flex items-center gap-2 mb-1 flex-wrap">
                  {/* Client Name with dot */}
                  <p className="text-[#ff5c8d] text-sm font-bold tracking-wide flex items-center gap-1">
                    <span className="w-1.5 h-1.5 rounded-full bg-[#ff5c8d]"></span>
                    {commission.clientName}
                  </p>
              </div>
              <h3 className="text-xl font-bold text-stone-700 leading-tight">{commission.title}</h3>
            </div>

            {isAdmin && (
              <div className="flex gap-2">
                  <button 
                    type="button"
                    onClick={() => onEdit(commission)}
                    className="p-2.5 rounded-xl bg-stone-50 text-stone-400 hover:text-blue-600 hover:bg-blue-50 transition-all duration-200 hover:scale-105"
                    title="編輯"
                  >
                    <Pencil size={18} />
                  </button>

                  <button 
                    type="button"
                    onClick={() => setShowAdminTools(!showAdminTools)}
                    className={`p-2.5 rounded-xl transition-all duration-200 ${showAdminTools ? 'bg-pink-100 text-pink-500 rotate-12 scale-110' : 'bg-stone-50 text-stone-400 hover:text-pink-500 hover:bg-pink-50 hover:scale-110'}`}
                    title="AI 小幫手"
                  >
                    <Sparkles size={18} />
                  </button>

                  <button 
                    type="button"
                    onClick={handleDeleteClick}
                    className={`p-2.5 rounded-xl transition-all duration-200 flex items-center gap-1 hover:scale-105 ${
                        isDeleting 
                        ? 'bg-red-500 text-white shadow-lg shadow-red-500/30 w-auto px-4' 
                        : 'bg-stone-50 text-stone-400 hover:text-red-500 hover:bg-red-50 w-10'
                    }`}
                    title="刪除"
                  >
                    {isDeleting ? (
                        <span className="text-xs font-bold whitespace-nowrap">確定?</span>
                    ) : (
                        <Trash2 size={18} />
                    )}
                  </button>
              </div>
            )}
          </div>

          <p className="text-stone-500 text-sm leading-relaxed mb-4 font-medium line-clamp-2 hover:line-clamp-none transition-all">
            {commission.description}
          </p>

          <div className="flex flex-wrap gap-2 text-xs text-stone-500 font-bold mb-4">
            <span className="flex items-center gap-1 bg-stone-50 px-2.5 py-1 rounded-md border border-stone-100">
              <Calendar size={12} className="text-stone-400" /> {commission.dateAdded}
            </span>
            <span className="flex items-center gap-1 bg-stone-50 px-2.5 py-1 rounded-md border border-stone-100">
              <DollarSign size={12} className="text-stone-400" /> {commission.price}
            </span>
            <span className="bg-[#ffa9c2]/10 px-2.5 py-1 rounded-md border border-[#ffa9c2]/20 text-[#ff5c8d]">
                {commission.type}
            </span>
          </div>
        </div>

        <div className="mt-auto bg-stone-50/50 rounded-2xl p-4 border border-stone-100">
          <ProgressBar currentStatus={commission.status} />

          {isAdmin && (
            <div className="flex justify-end gap-3 mt-4">
                <button 
                  type="button"
                  onClick={handlePrevStep}
                  disabled={commission.status === CommissionStatus.QUEUE}
                  className="flex items-center gap-1.5 px-4 py-1.5 text-xs font-bold text-stone-500 hover:text-stone-700 disabled:opacity-30 hover:bg-stone-100 rounded-full transition-all"
                >
                  <ChevronLeft size={14} /> 上一步
                </button>
                <button 
                  type="button"
                  onClick={handleNextStep}
                  disabled={commission.status === CommissionStatus.DONE}
                  className="flex items-center gap-1.5 px-5 py-1.5 text-xs font-bold bg-[#ffa9c2] hover:bg-[#ff94b3] text-white rounded-full transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-md shadow-pink-200 hover:-translate-y-0.5"
                >
                  下一步 <ChevronRight size={14} />
                </button>
            </div>
          )}
        </div>

        {isAdmin && showAdminTools && (
           <AdminTools commission={commission} onClose={() => setShowAdminTools(false)} />
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Commission, CommissionStatus, ThemeMode } from './types';
import { MOCK_COMMISSIONS } from './constants';
import { CommissionCard } from './components/CommissionCard';
import { AddCommissionForm } from './components/AddCommissionForm';
import { EditCommissionForm } from './components/EditCommissionForm';
import { Search, Sparkles, Lock, Unlock, Palette } from 'lucide-react';

const ARTIST_NAME = '百百嵂';

const App: React.FC = () => {
  // State
  const [commissions, setCommissions] = useState<Commission[]>([]);
  const [viewMode, setViewMode] = useState<ThemeMode>('client'); // Default is client
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<CommissionStatus | 'All'>('All');
  const [isAdding, setIsAdding] = useState(false);
  const [editingCommission, setEditingCommission] = useState<Commission | null>(null);

  // Data Loading State
  const [isLoaded, setIsLoaded] = useState(false);

  // Initialize Data
  useEffect(() => {
    const stored = localStorage.getItem('arttrack_commissions_zh_v1');
    if (stored) {
      try {
        let parsed = JSON.parse(stored);
        if (Array.isArray(parsed)) {
            // Force legacy data to match current artist
            parsed = parsed.map((c: any) => ({
                ...c,
                artistId: ARTIST_NAME
            }));
            setCommissions(parsed);
        } else {
            setCommissions(MOCK_COMMISSIONS);
        }
      } catch (e) {
        console.error("Failed to parse commissions from local storage", e);
        setCommissions(MOCK_COMMISSIONS);
      }
    } else {
      setCommissions(MOCK_COMMISSIONS);
    }
    setIsLoaded(true);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Persistence
  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem('arttrack_commissions_zh_v1', JSON.stringify(commissions));
    }
  }, [commissions, isLoaded]);

  // Handlers
  const handleUpdateStatus = (id: string, newStatus: CommissionStatus) => {
    setCommissions(prev => prev.map(c => 
      c.id === id ? { ...c, status: newStatus, lastUpdated: new Date().toISOString().split('T')[0] } : c
    ));
  };

  const handleDelete = (id: string) => {
    setCommissions(prev => prev.filter(c => c.id !== id));
  };

  const handleAdd = (newCommission: Commission) => {
    const commissionToAdd = {
        ...newCommission,
        artistId: ARTIST_NAME
    };
    setCommissions(prev => [commissionToAdd, ...prev]);
    setIsAdding(false);
  };

  const handleEdit = (updatedCommission: Commission) => {
    setCommissions(prev => prev.map(c => 
        c.id === updatedCommission.id ? updatedCommission : c
    ));
    setEditingCommission(null);
  };

  const toggleViewMode = () => {
    setViewMode(prev => prev === 'client' ? 'admin' : 'client');
  };

  // Filter Logic
  const filteredCommissions = useMemo(() => {
    return commissions.filter(c => {
      // Search & Filter
      const term = searchTerm.toLowerCase();
      const matchesSearch = 
        c.clientName.toLowerCase().includes(term) || 
        c.title.toLowerCase().includes(term) ||
        c.id.toLowerCase().includes(term);

      const matchesFilter = statusFilter === 'All' || c.status === statusFilter;

      return matchesSearch && matchesFilter;
    });
  }, [commissions, searchTerm, statusFilter]);

  // View Logic: Should we show the list?
  const shouldShowList = useMemo(() => {
    // Admin: Always show list
    if (viewMode === 'admin') {
          return true;
    }
    // Client: Must search to see results
    return searchTerm.trim().length > 0;
  }, [viewMode, searchTerm]);

  // Statistics
  const stats = useMemo(() => {
    return {
        queue: commissions.filter(c => c.status === CommissionStatus.QUEUE).length,
        active: commissions.filter(c => c.status !== CommissionStatus.QUEUE && c.status !== CommissionStatus.DONE).length,
        done: commissions.filter(c => c.status === CommissionStatus.DONE).length
    }
  }, [commissions]);

  return (
    <div className="min-h-screen bg-[#fffafb] text-stone-700 selection:bg-pink-200 flex flex-col">

      {/* Main Content */}
      <main className="flex-grow pt-12 pb-10 px-6 max-w-5xl mx-auto w-full">

        {/* Top Header */}
        <div className="flex items-center justify-between mb-8 text-[#ff5c8d] opacity-90">
            <div className="flex items-center gap-2">
                <div className="bg-[#ffa9c2] text-white p-1.5 rounded-lg shadow-sm transform -rotate-3">
                    <Sparkles size={18} />
                </div>
                <h1 className="text-xl font-bold tracking-wide">百百嵂的委託管理</h1>
            </div>

            {viewMode === 'admin' && (
                <div className="flex items-center gap-3">
                    <span className="text-sm font-bold bg-white px-3 py-1.5 rounded-full border border-stone-200 shadow-sm text-stone-600">
                        管理員模式
                    </span>
                </div>
            )}
        </div>

        {/* Intro / Stats */}
        <div className="mb-10 text-center sm:text-left sm:flex justify-between items-end animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="mb-8 sm:mb-0">
                <h2 className="text-3xl font-bold text-[#ff5c8d] mb-3 tracking-tight">
                    {viewMode === 'client' 
                        ? '委託進度查詢 ✨' 
                        : `歡迎回來，${ARTIST_NAME}！🎨`
                    }
                </h2>
                <p className="text-stone-500 max-w-lg font-medium leading-relaxed">
                    {viewMode === 'client' 
                        ? '請輸入您的委託 ID 或名稱，查看目前的繪製進度。' 
                        : '今天也要元氣滿滿的畫圖！這裡可以管理排單和進度喔。'}
                </p>
            </div>
            <div className="flex gap-3 justify-center sm:justify-end text-sm">
                <div className="bg-white border-2 border-stone-200 px-4 py-3 rounded-2xl text-center min-w-[80px] shadow-sm transform hover:-translate-y-1 transition-transform">
                    <div className="text-2xl font-bold text-stone-600">{stats.queue}</div>
                    <div className="text-xs text-stone-400 font-bold">排單中</div>
                </div>
                <div className="bg-white border-2 border-pink-100 px-4 py-3 rounded-2xl text-center min-w-[80px] shadow-sm transform hover:-translate-y-1 transition-transform">
                    <div className="text-2xl font-bold text-[#ff5c8d]">{stats.active}</div>
                    <div className="text-xs text-pink-400 font-bold">繪製中</div>
                </div>
                <div className="bg-white border-2 border-[#ffa9c2]/20 px-4 py-3 rounded-2xl text-center min-w-[80px] shadow-sm transform hover:-translate-y-1 transition-transform">
