import React, { useState } from 'react';
import { X, Plus, Trash2, Settings } from 'lucide-react';

interface TypeManagerProps {
  types: string[];
  onUpdateTypes: (newTypes: string[]) => void;
  onClose: () => void;
}

export const TypeManager: React.FC<TypeManagerProps> = ({ types, onUpdateTypes, onClose }) => {
  const [newType, setNewType] = useState('');

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (newType.trim() && !types.includes(newType.trim())) {
      onUpdateTypes([...types, newType.trim()]);
      setNewType('');
    }
  };

  const handleDelete = (typeToDelete: string) => {
    if (confirm(`確定要刪除「${typeToDelete}」這個類型嗎？`)) {
        onUpdateTypes(types.filter(t => t !== typeToDelete));
