            </div>
            管理委託類型
          </h3>
          <button onClick={onClose} className="text-stone-400 hover:text-stone-600 transition-colors">
            <X size={20} />
          </button>
        </div>

        {/* Add New */}
        <form onSubmit={handleAdd} className="flex gap-2 mb-6">
          <input
            type="text"
            value={newType}
            onChange={(e) => setNewType(e.target.value)}
            placeholder="輸入新類型名稱..."
            className="flex-grow bg-stone-50 border-2 border-stone-200 rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-[#ffa9c2]/50 focus:border-[#ffa9c2] focus:outline-none"
          />
          <button 
            type="submit"
            disabled={!newType.trim()}
            className="bg-[#ffa9c2] hover:bg-[#ff94b3] text-white p-2 rounded-xl disabled:opacity-50 transition-colors"
          >
            <Plus size={20} />
          </button>
        </form>

        {/* List */}
        <div className="space-y-2 max-h-[300px] overflow-y-auto pr-1 custom-scrollbar">
          {types.map((type) => (
            <div key={type} className="flex justify-between items-center bg-stone-50 px-4 py-3 rounded-xl border border-stone-100 group hover:border-pink-200 transition-colors">
              <span className="font-bold text-stone-600 text-sm">{type}</span>
              <button
                onClick={() => handleDelete(type)}
                className="text-stone-300 hover:text-red-400 p-1 rounded-md hover:bg-red-50 transition-all opacity-0 group-hover:opacity-100"
                title="刪除"
              >
                <Trash2 size={16} />
              </button>
            </div>
          ))}
        </div>

        <div className="mt-6 text-center">
            <button 
                onClick={onClose}
                className="text-stone-400 text-xs font-bold hover:text-stone-600 underline decoration-2 decoration-stone-200 underline-offset-4"
            >
                完成編輯
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
