interface AddCommissionFormProps {
  onAdd: (c: Commission) => void;
  onCancel: () => void;
  availableTypes: string[];
  onManageTypes: () => void;
}

export const AddCommissionForm: React.FC<AddCommissionFormProps> = ({ onAdd, onCancel, availableTypes, onManageTypes }) => {
  // Set default type to the first available type or empty
  const defaultType = availableTypes.length > 0 ? availableTypes[0] : '';

  const [formData, setFormData] = useState<Partial<Commission>>({
    clientName: '',
    title: '',
    description: '',
    type: defaultType,
    price: 0,
    status: CommissionStatus.QUEUE,
    thumbnailUrl: ''
  });

  // Effect to ensure type is valid if availableTypes changes
  useEffect(() => {
    if (availableTypes.length > 0 && (!formData.type || !availableTypes.includes(formData.type))) {
        setFormData(prev => ({ ...prev, type: availableTypes[0] }));
    }
  }, [availableTypes, formData.type]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        // Limit file size to 800KB to avoid localStorage quota issues
