        <div className="flex justify-center">
            <button 
                onClick={handleModeSwitchRequest}
                className={`p-2 rounded-full transition-all duration-300 ${viewMode === 'admin' ? 'bg-stone-200 text-stone-600 hover:bg-stone-300' : 'text-stone-300 hover:text-stone-400 hover:bg-stone-100'}`}
                title={viewMode === 'client' ? "管理員登入" : "登出管理模式"}
            >
                {viewMode === 'admin' ? <Unlock size={16} /> : <Lock size={16} />}
            </button>
        </div>
      </footer>
    </div>
  );

  return (
    <div className="bg-[#fffafb] text-stone-700 selection:bg-pink-200">

      {/* Global Modals */}
      {showTypeManager && (
          <TypeManager 
            types={commissionTypes}
            onUpdateTypes={setCommissionTypes}
            onClose={() => setShowTypeManager(false)}
          />
      )}

      {/* Auth Modal */}
      {showAuthModal && (
        <div className="fixed inset-0 bg-stone-900/40 backdrop-blur-sm z-[100] flex items-center justify-center p-4 animate-in fade-in duration-200">
            <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl border-4 border-pink-100 animate-in zoom-in-95 duration-200 relative">
                <button 
                    onClick={() => setShowAuthModal(false)}
                    className="absolute top-4 right-4 text-stone-300 hover:text-stone-500 transition-colors"
                >
                    <X size={20} />
                </button>

                <div className="flex flex-col items-center mb-6">
                    <div className="w-16 h-16 bg-pink-100 rounded-2xl flex items-center justify-center text-[#ff5c8d] mb-4 shadow-inner">
                        <Lock size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-stone-700">管理員登入</h3>
                    <p className="text-stone-400 text-sm font-medium mt-1">請輸入密碼以進行管理</p>
                </div>

                <form onSubmit={handleAuthSubmit} className="space-y-4">
                    <div className="relative">
                        <Key size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" />
                        <input 
                            id="password-input"
                            ref={passwordInputRef}
                            type="password"
                            value={passwordInput}
                            onChange={(e) => {
                                setPasswordInput(e.target.value);
                                setAuthError(false);
                            }}
                            className={`w-full bg-stone-50 border-2 ${authError ? 'border-red-400 focus:border-red-400 focus:ring-red-100' : 'border-stone-200 focus:border-[#ffa9c2] focus:ring-[#ffa9c2]/20'} rounded-2xl pl-10 pr-4 py-3 text-stone-700 focus:ring-4 focus:outline-none font-bold tracking-wider transition-all placeholder:font-normal placeholder:tracking-normal`}
                            placeholder="輸入密碼..."
                        />
                    </div>

                    {authError && (
                        <p className="text-red-500 text-xs font-bold text-center animate-in slide-in-from-top-1">
                            密碼錯誤，請再試一次
                        </p>
                    )}

                    <button 
                        type="submit"
                        className="w-full bg-[#ffa9c2] hover:bg-[#ff94b3] text-white font-bold py-3 px-4 rounded-2xl transition-all shadow-lg shadow-pink-200 hover:-translate-y-0.5 active:scale-95 flex items-center justify-center gap-2"
                    >
                        解鎖進入 <ChevronRight size={16} />
                    </button>
                </form>
            </div>
        </div>
      )}

      {/* Edit Overlay */}
      {editingCommission && (
          <EditCommissionForm 
            commission={editingCommission} 
            onSave={handleEdit} 
            onCancel={() => setEditingCommission(null)} 
            availableTypes={commissionTypes}
            onManageTypes={() => setShowTypeManager(true)}
          />
      )}

      {/* Page Routing */}
      {currentPage === 'home' && renderHome()}
      {currentPage === 'request' && renderRequest()}
      {currentPage === 'tracking' && renderTracking()}

    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Commission, CommissionStatus, ThemeMode } from './types';
import { MOCK_COMMISSIONS, DEFAULT_COMMISSION_TYPES } from './constants';
import { CommissionCard } from './components/CommissionCard';
