import React, { useState } from 'react';
import { X, Plus, Trash2, Settings, DollarSign } from 'lucide-react';
import { CommissionType } from '../types';

interface TypeManagerProps {
  types: CommissionType[];
  onUpdateTypes: (newTypes: CommissionType[]) => void;
  onClose: () => void;
}

export const TypeManager: React.FC<TypeManagerProps> = ({ types, onUpdateTypes, onClose }) => {
  const [newTypeName, setNewTypeName] = useState('');
  const [newTypePrice, setNewTypePrice] = useState<string>('');

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (newTypeName.trim() && !types.some(t => t.name === newTypeName.trim())) {
      // Check if price is a number
      const parsedPrice = Number(newTypePrice);
      const finalPrice = isNaN(parsedPrice) && newTypePrice !== '' ? newTypePrice : (parsedPrice || 0);

      onUpdateTypes([
        ...types, 
        { name: newTypeName.trim(), price: finalPrice }
      ]);
      setNewTypeName('');
      setNewTypePrice('');
    }
  };

  const handleDelete = (typeNameToDelete: string) => {
    if (confirm(`確定要刪除「${typeNameToDelete}」這個類型嗎？`)) {
        onUpdateTypes(types.filter(t => t.name !== typeNameToDelete));
    }
  };

  const handlePriceUpdate = (typeName: string, newValue: string) => {
      const parsed = Number(newValue);
      const finalValue = isNaN(parsed) && newValue !== '' ? newValue : parsed;

      onUpdateTypes(types.map(t => 
        t.name === typeName ? { ...t, price: finalValue } : t
      ));
  };

  return (
    <div className="fixed inset-0 bg-stone-900/40 backdrop-blur-sm z-[60] flex items-center justify-center p-4 animate-in fade-in duration-200">
      <div className="bg-white rounded-3xl p-6 max-w-md w-full shadow-2xl border-2 border-pink-100 animate-in zoom-in-95 duration-200">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-bold text-stone-700 flex items-center gap-2">
            <div className="bg-pink-100 p-2 rounded-lg text-[#ff5c8d]">
                <Settings size={20} />
            </div>
            管理委託項目與價格
          </h3>
          <button onClick={onClose} className="text-stone-400 hover:text-stone-600 transition-colors">
            <X size={20} />
          </button>
        </div>

        {/* Add New */}
        <form onSubmit={handleAdd} className="flex gap-2 mb-6 items-end">
          <div className="flex-grow space-y-1">
              <label className="text-xs font-bold text-stone-400 ml-1">項目名稱</label>
              <input
                type="text"
                value={newTypeName}
                onChange={(e) => setNewTypeName(e.target.value)}
                placeholder="例如: 全身立繪"
                className="w-full bg-stone-50 border-2 border-stone-200 rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-[#ffa9c2]/50 focus:border-[#ffa9c2] focus:outline-none"
              />
          </div>
          <div className="w-28 space-y-1">
              <label className="text-xs font-bold text-stone-400 ml-1">預設價格</label>
              <input
                type="text"
                value={newTypePrice}
                onChange={(e) => setNewTypePrice(e.target.value)}
                placeholder="$$$ 或 自帶價"
                className="w-full bg-stone-50 border-2 border-stone-200 rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-[#ffa9c2]/50 focus:border-[#ffa9c2] focus:outline-none text-right"
              />
          </div>
          <button 
            type="submit"
            disabled={!newTypeName.trim()}
            className="bg-[#ffa9c2] hover:bg-[#ff94b3] text-white p-2.5 rounded-xl disabled:opacity-50 transition-colors h-[42px] mb-[1px]"
          >
            <Plus size={20} />
          </button>
        </form>

        {/* List */}
        <div className="space-y-2 max-h-[300px] overflow-y-auto pr-1 custom-scrollbar">
          {types.map((type) => (
            <div key={type.name} className="flex justify-between items-center bg-stone-50 px-4 py-3 rounded-xl border border-stone-100 group hover:border-pink-200 transition-colors">
              <span className="font-bold text-stone-600 text-sm">{type.name}</span>

              <div className="flex items-center gap-3">
                  <div className="flex items-center gap-1 bg-white px-2 py-1 rounded-md border border-stone-200">
                      {typeof type.price === 'number' && <DollarSign size={12} className="text-stone-400"/>}
                      <input 
                        type="text"
                        className="w-20 text-right text-sm font-bold text-stone-600 focus:outline-none bg-transparent"
                        value={type.price}
                        onChange={(e) => handlePriceUpdate(type.name, e.target.value)}
                      />
                  </div>
                  <button
                    onClick={() => handleDelete(type.name)}
                    className="text-stone-300 hover:text-red-400 p-1 rounded-md hover:bg-red-50 transition-all"
                    title="刪除"
                  >
                    <Trash2 size={16} />
                  </button>
              </div>
            </div>
          ))}
        </div>

        <div className="mt-6 text-center">
            <button 
                onClick={onClose}
                className="text-stone-400 text-xs font-bold hover:text-stone-600 underline decoration-2 decoration-stone-200 underline-offset-4"
            >
                完成編輯
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Commission, CommissionStatus, ThemeMode, CommissionType } from './types';
import { MOCK_COMMISSIONS, DEFAULT_COMMISSION_TYPES } from './constants';
import { CommissionCard } from './components/CommissionCard';
import { AddCommissionForm } from './components/AddCommissionForm';
import { ClientRequestForm } from './components/ClientRequestForm';
import { EditCommissionForm } from './components/EditCommissionForm';
import { TypeManager } from './components/TypeManager';
import { Search, Sparkles, Lock, Unlock, Palette, Key, X, ChevronRight, Home, PenTool, LayoutDashboard, Power, Ban, DollarSign } from 'lucide-react';

const ARTIST_NAME = '百百嵂';
const ADMIN_PASSWORD = 'X90058';

type Page = 'home' | 'tracking' | 'request';

const App: React.FC = () => {
  // Navigation State
  const [currentPage, setCurrentPage] = useState<Page>('home');

  // Data State
  const [commissions, setCommissions] = useState<Commission[]>([]);
  const [commissionTypes, setCommissionTypes] = useState<CommissionType[]>([]);
  const [isCommissionsOpen, setIsCommissionsOpen] = useState(true);

  // View/Filter State
  const [viewMode, setViewMode] = useState<ThemeMode>('client'); // Default is client
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<CommissionStatus | 'All'>('All');
  const [isAdding, setIsAdding] = useState(false);
  const [editingCommission, setEditingCommission] = useState<Commission | null>(null);
  const [showTypeManager, setShowTypeManager] = useState(false);

  // Auth State
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [authError, setAuthError] = useState(false);

  // Data Loading State
  const [isLoaded, setIsLoaded] = useState(false);

  const passwordInputRef = useRef<HTMLInputElement>(null);

  // Initialize Data
  useEffect(() => {
    // Load Commissions
    const storedCommissions = localStorage.getItem('arttrack_commissions_zh_v1');
    if (storedCommissions) {
      try {
        let parsed = JSON.parse(storedCommissions);
        if (Array.isArray(parsed)) {
            parsed = parsed.map((c: any) => ({
                ...c,
                artistId: ARTIST_NAME
            }));
            setCommissions(parsed);
        } else {
            setCommissions(MOCK_COMMISSIONS);
        }
      } catch (e) {
        setCommissions(MOCK_COMMISSIONS);
      }
    } else {
      setCommissions(MOCK_COMMISSIONS);
    }

    // Load Types
    const storedTypes = localStorage.getItem('arttrack_types_v1');
    if (storedTypes) {
        try {
            const parsedTypes = JSON.parse(storedTypes);
            if (Array.isArray(parsedTypes) && parsedTypes.length > 0) {
                // Migration logic: if old types were just strings
                if (typeof parsedTypes[0] === 'string') {
                    const migrated = (parsedTypes as unknown as string[]).map(name => {
                         const def = DEFAULT_COMMISSION_TYPES.find(d => d.name === name);
                         return { name, price: def ? def.price : 0 };
                    });
                    setCommissionTypes(migrated);
                } else {
                    setCommissionTypes(parsedTypes);
                }
            } else {
                setCommissionTypes(DEFAULT_COMMISSION_TYPES);
            }
        } catch(e) {
            setCommissionTypes(DEFAULT_COMMISSION_TYPES);
        }
    } else {
        setCommissionTypes(DEFAULT_COMMISSION_TYPES);
    }

    // Load Commission Status (Open/Closed)
    const storedStatus = localStorage.getItem('arttrack_status_v1');
    if (storedStatus) {
        setIsCommissionsOpen(storedStatus === 'true');
    }

    setIsLoaded(true);
  }, []);

  // Auto-focus password input when modal opens
  useEffect(() => {
    if (showAuthModal && passwordInputRef.current) {
        setTimeout(() => passwordInputRef.current?.focus(), 100);
    }
  }, [showAuthModal]);

  // Persistence
  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem('arttrack_commissions_zh_v1', JSON.stringify(commissions));
      localStorage.setItem('arttrack_types_v1', JSON.stringify(commissionTypes));
      localStorage.setItem('arttrack_status_v1', String(isCommissionsOpen));
    }
  }, [commissions, commissionTypes, isCommissionsOpen, isLoaded]);

  // Handlers
  const handleUpdateStatus = (id: string, newStatus: CommissionStatus) => {
    setCommissions(prev => prev.map(c => 
      c.id === id ? { ...c, status: newStatus, lastUpdated: new Date().toISOString().split('T')[0] } : c
    ));
  };

  const handleDelete = (id: string) => {
    setCommissions(prev => prev.filter(c => c.id !== id));
  };

  const handleAdd = (newCommission: Commission) => {
    const commissionToAdd = {
        ...newCommission,
        artistId: ARTIST_NAME
    };
    setCommissions(prev => [commissionToAdd, ...prev]);
    setIsAdding(false);
  };

  // Special handler for public requests (does not close admin modal, but redirects)
  const handleClientRequestSubmit = (newCommission: Commission) => {
     const commissionToAdd = {
        ...newCommission,
        artistId: ARTIST_NAME
    };
    setCommissions(prev => [commissionToAdd, ...prev]);
    // Stay on success screen handled by the form component, or we could redirect
  };

  const handleEdit = (updatedCommission: Commission) => {
    setCommissions(prev => prev.map(c => 
        c.id === updatedCommission.id ? updatedCommission : c
    ));
    setEditingCommission(null);
  };

  const handleModeSwitchRequest = () => {
    if (viewMode === 'admin') {
        setViewMode('client');
    } else {
        setShowAuthModal(true);
        setPasswordInput('');
        setAuthError(false);
    }
  };

  const handleAuthSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ADMIN_PASSWORD) {
        setViewMode('admin');
        setShowAuthModal(false);
        setPasswordInput('');
        setCurrentPage('tracking'); // Redirect to dashboard immediately after login
    } else {
        setAuthError(true);
        // Use ref for cleaner React approach, fallback to getElementById if ref isn't attached for some reason
        const input = passwordInputRef.current || document.getElementById('password-input');
        if (input) {
            input.classList.remove('animate-shake');
            void input.offsetWidth; // trigger reflow
            input.classList.add('animate-shake');
        }
    }
  };

  const toggleCommissionStatus = () => {
      if (viewMode === 'admin') {
          setIsCommissionsOpen(!isCommissionsOpen);
      }
  };

  // Filter Logic
  const filteredCommissions = useMemo(() => {
    return commissions.filter(c => {
      // Search & Filter
      const term = searchTerm.toLowerCase();
      const matchesSearch = 
        c.clientName.toLowerCase().includes(term) || 
        c.title.toLowerCase().includes(term) ||
        c.id.toLowerCase().includes(term);

      const matchesFilter = statusFilter === 'All' || c.status === statusFilter;

      return matchesSearch && matchesFilter;
    });
  }, [commissions, searchTerm, statusFilter]);

  // View Logic: Should we show the list?
  const shouldShowList = useMemo(() => {
    if (viewMode === 'admin') return true;
    return searchTerm.trim().length > 0;
  }, [viewMode, searchTerm]);

  // Statistics
  const stats = useMemo(() => {
    const totalRevenue = commissions.reduce((sum, c) => {
        const p = Number(c.price);
        return sum + (isNaN(p) ? 0 : p);
    }, 0);

    return {
        queue: commissions.filter(c => c.status === CommissionStatus.QUEUE).length,
        active: commissions.filter(c => c.status !== CommissionStatus.QUEUE && c.status !== CommissionStatus.DONE).length,
        done: commissions.filter(c => c.status === CommissionStatus.DONE).length,
        total: totalRevenue
    }
  }, [commissions]);

  // --- Render Sections ---

  const renderHome = () => (
    <div className="min-h-screen flex flex-col items-center justify-center p-6 animate-in fade-in duration-500 relative overflow-hidden">
        {/* Decorative blobs */}
        <div className="absolute top-[-10%] left-[-10%] w-64 h-64 bg-pink-200 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob"></div>
        <div className="absolute top-[-10%] right-[-10%] w-64 h-64 bg-[#ffa9c2] rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-2000"></div>
        <div className="absolute bottom-[-20%] left-[20%] w-80 h-80 bg-purple-200 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-4000"></div>

        <div className="text-center mb-12 relative z-10">
            <div className="bg-white p-4 rounded-3xl shadow-xl shadow-pink-100 inline-block mb-6 transform -rotate-3 hover:rotate-0 transition-transform duration-300">
                 <Sparkles size={48} className="text-[#ff5c8d]" />
            </div>
            <h1 className="text-4xl md:text-5xl font-black text-stone-700 tracking-tight mb-4">
                百百嵂的委託小舖
            </h1>
            <p className="text-stone-400 text-lg font-medium">
                歡迎光臨！請選擇您需要的服務 🎨
            </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full max-w-2xl relative z-10">
            {/* Request Button */}
            <button 
                onClick={() => isCommissionsOpen && setCurrentPage('request')}
                disabled={!isCommissionsOpen}
                className={`group rounded-[2.5rem] p-8 text-left transition-all duration-300 
                    ${isCommissionsOpen 
                        ? 'bg-[#ffa9c2] hover:bg-[#ff94b3] text-white hover:-translate-y-2 hover:shadow-xl hover:shadow-pink-200 cursor-pointer' 
                        : 'bg-stone-200 text-stone-400 cursor-not-allowed border-4 border-stone-100'
                    }`}
            >
                <div className={`w-16 h-16 rounded-2xl flex items-center justify-center mb-6 transition-transform backdrop-blur-sm
                     ${isCommissionsOpen ? 'bg-white/20 text-white group-hover:scale-110' : 'bg-stone-300 text-stone-500'}
                `}>
                    {isCommissionsOpen ? <PenTool size={32} /> : <Ban size={32} />}
                </div>
                <h2 className="text-2xl font-bold mb-2">
                    {isCommissionsOpen ? '我要委託' : '暫停接單'}
                </h2>
                <p className={`font-medium ${isCommissionsOpen ? 'text-pink-100' : 'text-stone-400'}`}>
                    {isCommissionsOpen 
                        ? '喜歡我的畫風嗎？\n填寫表單送出您的委託需求！' 
                        : '目前排單已滿或休息中，\n請關注後續公告開啟時間。'
                    }
                </p>
            </button>

            {/* Tracking Button */}
            <button 
                onClick={() => setCurrentPage('tracking')}
                className="group bg-white hover:bg-stone-50 border-4 border-stone-100 hover:border-pink-200 rounded-[2.5rem] p-8 text-left transition-all duration-300 hover:-translate-y-2 hover:shadow-xl hover:shadow-pink-100"
            >
                <div className="bg-pink-50 w-16 h-16 rounded-2xl flex items-center justify-center text-[#ff5c8d] mb-6 group-hover:scale-110 transition-transform">
                    <Search size={32} />
                </div>
                <h2 className="text-2xl font-bold text-stone-700 mb-2">委託進度追蹤</h2>
                <p className="text-stone-400 font-medium">已經有委託了嗎？<br/>輸入 ID 查詢目前的繪製進度。</p>
            </button>
        </div>

        <div className="mt-12 flex flex-col items-center gap-4 relative z-10">
            <div className="text-stone-300 text-sm font-bold">
                © 2026 CommissionTrack
            </div>

            <button 
                onClick={handleModeSwitchRequest}
                className={`p-2 rounded-full transition-all duration-300 ${viewMode === 'admin' ? 'bg-stone-200 text-stone-600 hover:bg-stone-300' : 'text-stone-300 hover:text-stone-400 hover:bg-pink-50'}`}
                title={viewMode === 'client' ? "管理員登入" : "登出管理模式"}
            >
                {viewMode === 'admin' ? <Unlock size={16} /> : <Lock size={16} />}
            </button>
        </div>
    </div>
  );

  const renderRequest = () => (
      <div className="min-h-screen pt-8 pb-10 px-4">
          <div className="max-w-3xl mx-auto mb-6">
              <button 
                onClick={() => setCurrentPage('home')}
                className="flex items-center gap-2 text-stone-400 hover:text-stone-600 font-bold bg-white px-4 py-2 rounded-full shadow-sm hover:shadow-md transition-all"
              >
                  <Home size={18} /> 返回首頁
              </button>
          </div>
          <ClientRequestForm 
            availableTypes={commissionTypes}
            onSubmit={handleClientRequestSubmit}
            onCancel={() => setCurrentPage('home')}
          />
      </div>
  );

  const renderTracking = () => (
    <div className="min-h-screen flex flex-col relative">
      {/* Top Header */}
      <div className="pt-8 px-6 max-w-5xl mx-auto w-full">
         <div className="flex items-center justify-between mb-8 text-[#ff5c8d] opacity-90">
            <div className="flex items-center gap-3">
                 <button 
                    onClick={() => setCurrentPage('home')}
                    className="bg-white p-2 rounded-full shadow-sm text-stone-400 hover:text-[#ff5c8d] transition-colors"
                  >
                      <Home size={20} />
                  </button>
                <h1 className="text-xl font-bold tracking-wide">委託進度管理</h1>
            </div>

            {viewMode === 'admin' && (
                <div className="flex items-center gap-3">
                     {/* Commission Toggle Switch */}
                     <button
                        onClick={toggleCommissionStatus}
                        className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold border transition-all
                            ${isCommissionsOpen 
                                ? 'bg-green-100 text-green-600 border-green-200 hover:bg-green-200' 
                                : 'bg-stone-200 text-stone-500 border-stone-300 hover:bg-stone-300'
                            }`}
                        title={isCommissionsOpen ? "目前開放中 (點擊關閉)" : "目前關閉中 (點擊開放)"}
                     >
                        <Power size={14} />
                        {isCommissionsOpen ? '接單中' : '暫停中'}
                     </button>

                    <span className="text-sm font-bold bg-white px-3 py-1.5 rounded-full border border-stone-200 shadow-sm text-stone-600 animate-in fade-in flex items-center gap-2">
                        <LayoutDashboard size={14}/> 管理員模式
                    </span>
                </div>
