        </div>
      </div>

      {/* Footer with Admin Switch */}
      <footer className="py-8 border-t border-stone-200 text-center mt-auto">
        <p className="text-stone-400 text-sm font-medium mb-4">
            © 2026 CommissionTrack
        </p>

        <div className="flex justify-center">
            <button 
                onClick={handleModeSwitchRequest}
                className={`p-2 rounded-full transition-all duration-300 ${viewMode === 'admin' ? 'bg-stone-200 text-stone-600 hover:bg-stone-300' : 'text-stone-300 hover:text-stone-400 hover:bg-stone-100'}`}
                title={viewMode === 'client' ? "管理員登入" : "登出管理模式"}
            >
                {viewMode === 'admin' ? <Unlock size={16} /> : <Lock size={16} />}
            </button>
        </div>
      </footer>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#fffafb] font-sans text-stone-600 selection:bg-pink-100">
      {currentPage === 'home' && renderHome()}
      {currentPage === 'request' && renderRequest()}
      {currentPage === 'tracking' && renderTracking()}

      {/* Auth Modal */}
      {showAuthModal && (
        <div className="fixed inset-0 bg-stone-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl border-2 border-white animate-in zoom-in-95 relative overflow-hidden">
            <button
              onClick={() => setShowAuthModal(false)}
              className="absolute top-4 right-4 text-stone-300 hover:text-stone-500"
            >
              <X size={20} />
            </button>

            <div className="text-center mb-6">
              <div className="w-16 h-16 bg-pink-50 rounded-2xl flex items-center justify-center mx-auto mb-4 text-[#ff5c8d]">
                <Key size={32} />
              </div>
              <h3 className="text-xl font-bold text-stone-700">管理員登入</h3>
              <p className="text-stone-400 text-sm mt-1">請輸入密碼以進入管理模式</p>
            </div>

            <form onSubmit={handleAuthSubmit}>
              <input
                id="password-input"
                ref={passwordInputRef}
                type="password"
                className={`w-full bg-stone-50 border-2 rounded-xl px-4 py-3 text-center tracking-widest font-bold text-stone-600 focus:outline-none focus:border-[#ffa9c2] transition-all mb-4 ${authError ? 'border-red-300 bg-red-50 animate-shake' : 'border-stone-200'}`}
                value={passwordInput}
                onChange={(e) => {
                  setPasswordInput(e.target.value);
                  setAuthError(false);
                }}
                placeholder="••••••"
              />
              <button
                type="submit"
                className="w-full bg-[#ffa9c2] hover:bg-[#ff94b3] text-white font-bold py-3 rounded-xl shadow-lg shadow-pink-200 hover:-translate-y-0.5 transition-all"
              >
                登入
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Type Manager Modal */}
      {viewMode === 'admin' && showTypeManager && (
        <TypeManager
          types={commissionTypes}
          onUpdateTypes={(newTypes) => setCommissionTypes(newTypes)}
          onClose={() => setShowTypeManager(false)}
        />
      )}

      {/* Edit Commission Modal */}
      {viewMode === 'admin' && editingCommission && (
        <EditCommissionForm
          commission={editingCommission}
          onSave={handleEdit}
          onCancel={() => setEditingCommission(null)}
          availableTypes={commissionTypes}
          onManageTypes={() => setShowTypeManager(true)}
        />
      )}
    </div>
  );
};

export default App;

