};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Commission, CommissionStatus, ThemeMode, CommissionType } from './types';
import { MOCK_COMMISSIONS, DEFAULT_COMMISSION_TYPES } from './constants';
import { CommissionCard } from './components/CommissionCard';
import { AddCommissionForm } from './components/AddCommissionForm';
import { ClientRequestForm } from './components/ClientRequestForm';
import { EditCommissionForm } from './components/EditCommissionForm';
import { TypeManager } from './components/TypeManager';
import { Search, Sparkles, Lock, Unlock, Palette, Key, X, ChevronRight, Home, PenTool, LayoutDashboard, Power, Ban, DollarSign } from 'lucide-react';

const ARTIST_NAME = '百百嵂';
const ADMIN_PASSWORD = 'X90058';

type Page = 'home' | 'tracking' | 'request';

const App: React.FC = () => {
  // Navigation State
  const [currentPage, setCurrentPage] = useState<Page>('home');

  // Data State
  const [commissions, setCommissions] = useState<Commission[]>([]);
  const [commissionTypes, setCommissionTypes] = useState<CommissionType[]>([]);
  const [isCommissionsOpen, setIsCommissionsOpen] = useState(true);

  // View/Filter State
  const [viewMode, setViewMode] = useState<ThemeMode>('client'); // Default is client
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<CommissionStatus | 'All'>('All');
  const [isAdding, setIsAdding] = useState(false);
  const [editingCommission, setEditingCommission] = useState<Commission | null>(null);
  const [showTypeManager, setShowTypeManager] = useState(false);

  // Auth State
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [authError, setAuthError] = useState(false);

  // Data Loading State
  const [isLoaded, setIsLoaded] = useState(false);

  const passwordInputRef = useRef<HTMLInputElement>(null);

  // Initialize Data
  useEffect(() => {
    // Load Commissions
    const storedCommissions = localStorage.getItem('arttrack_commissions_zh_v1');
    if (storedCommissions) {
      try {
        let parsed = JSON.parse(storedCommissions);
        if (Array.isArray(parsed)) {
            parsed = parsed.map((c: any) => ({
                ...c,
                artistId: ARTIST_NAME
            }));
            setCommissions(parsed);
        } else {
            setCommissions(MOCK_COMMISSIONS);
        }
      } catch (e) {
        setCommissions(MOCK_COMMISSIONS);
      }
    } else {
      setCommissions(MOCK_COMMISSIONS);
    }

    // Load Types
    const storedTypes = localStorage.getItem('arttrack_types_v1');
    if (storedTypes) {
        try {
            const parsedTypes = JSON.parse(storedTypes);
            if (Array.isArray(parsedTypes) && parsedTypes.length > 0) {
                // Migration logic: if old types were just strings
                if (typeof parsedTypes[0] === 'string') {
                    const migrated = (parsedTypes as unknown as string[]).map(name => {
                         const def = DEFAULT_COMMISSION_TYPES.find(d => d.name === name);
                         return { name, price: def ? def.price : 0 };
                    });
                    setCommissionTypes(migrated);
                } else {
                    setCommissionTypes(parsedTypes);
                }
            } else {
                setCommissionTypes(DEFAULT_COMMISSION_TYPES);
            }
        } catch(e) {
            setCommissionTypes(DEFAULT_COMMISSION_TYPES);
        }
    } else {
        setCommissionTypes(DEFAULT_COMMISSION_TYPES);
    }

    // Load Commission Status (Open/Closed)
    const storedStatus = localStorage.getItem('arttrack_status_v1');
    if (storedStatus) {
        setIsCommissionsOpen(storedStatus === 'true');
    }

    setIsLoaded(true);
  }, []);

  // Auto-focus password input when modal opens
  useEffect(() => {
    if (showAuthModal && passwordInputRef.current) {
        setTimeout(() => passwordInputRef.current?.focus(), 100);
    }
  }, [showAuthModal]);

  // Persistence
  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem('arttrack_commissions_zh_v1', JSON.stringify(commissions));
      localStorage.setItem('arttrack_types_v1', JSON.stringify(commissionTypes));
      localStorage.setItem('arttrack_status_v1', String(isCommissionsOpen));
    }
  }, [commissions, commissionTypes, isCommissionsOpen, isLoaded]);

  // Handlers
  const handleUpdateStatus = (id: string, newStatus: CommissionStatus) => {
    setCommissions(prev => prev.map(c => 
      c.id === id ? { ...c, status: newStatus, lastUpdated: new Date().toISOString().split('T')[0] } : c
    ));
  };

  const handleDelete = (id: string) => {
    setCommissions(prev => prev.filter(c => c.id !== id));
  };

  const handleAdd = (newCommission: Commission) => {
    const commissionToAdd = {
        ...newCommission,
        artistId: ARTIST_NAME
    };
    setCommissions(prev => [commissionToAdd, ...prev]);
    setIsAdding(false);
  };

  // Special handler for public requests (does not close admin modal, but redirects)
  const handleClientRequestSubmit = (newCommission: Commission) => {
     const commissionToAdd = {
        ...newCommission,
        artistId: ARTIST_NAME
    };
    setCommissions(prev => [commissionToAdd, ...prev]);
    // Stay on success screen handled by the form component, or we could redirect
  };

  const handleEdit = (updatedCommission: Commission) => {
    setCommissions(prev => prev.map(c => 
        c.id === updatedCommission.id ? updatedCommission : c
    ));
    setEditingCommission(null);
  };

  const handleModeSwitchRequest = () => {
    if (viewMode === 'admin') {
        setViewMode('client');
    } else {
        setShowAuthModal(true);
        setPasswordInput('');
        setAuthError(false);
    }
  };

  const handleAuthSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ADMIN_PASSWORD) {
        setViewMode('admin');
        setShowAuthModal(false);
        setPasswordInput('');
        setCurrentPage('tracking'); // Redirect to dashboard immediately after login
    } else {
        setAuthError(true);
        // Use ref for cleaner React approach, fallback to getElementById if ref isn't attached for some reason
        const input = passwordInputRef.current || document.getElementById('password-input');
        if (input) {
            input.classList.remove('animate-shake');
            void input.offsetWidth; // trigger reflow
            input.classList.add('animate-shake');
        }
    }
  };

  const toggleCommissionStatus = () => {
      if (viewMode === 'admin') {
          setIsCommissionsOpen(!isCommissionsOpen);
      }
  };

  // Filter Logic
  const filteredCommissions = useMemo(() => {
    return commissions.filter(c => {
      // Search & Filter
      const term = searchTerm.toLowerCase();
      const matchesSearch = 
        c.clientName.toLowerCase().includes(term) || 
        c.title.toLowerCase().includes(term) ||
        c.id.toLowerCase().includes(term);

      const matchesFilter = statusFilter === 'All' || c.status === statusFilter;

      return matchesSearch && matchesFilter;
    });
  }, [commissions, searchTerm, statusFilter]);

  // View Logic: Should we show the list?
  const shouldShowList = useMemo(() => {
    if (viewMode === 'admin') return true;
    return searchTerm.trim().length > 0;
  }, [viewMode, searchTerm]);

  // Statistics
  const stats = useMemo(() => {
    const now = new Date();
    const currentYear = now.getFullYear();
    const currentMonth = now.getMonth();

    const monthlyRevenue = commissions.reduce((sum, c) => {
        // Parse dateAdded (format YYYY-MM-DD)
        const cDate = new Date(c.dateAdded);

        // Check if the commission was added in the current month and year
        if (!isNaN(cDate.getTime()) && 
            cDate.getFullYear() === currentYear && 
            cDate.getMonth() === currentMonth) {

            const p = Number(c.price);
            return sum + (isNaN(p) ? 0 : p);
        }
        return sum;
    }, 0);

    return {
        queue: commissions.filter(c => c.status === CommissionStatus.QUEUE).length,
        active: commissions.filter(c => c.status !== CommissionStatus.QUEUE && c.status !== CommissionStatus.DONE).length,
        done: commissions.filter(c => c.status === CommissionStatus.DONE).length,
        total: monthlyRevenue
    }
  }, [commissions]);

  // --- Render Sections ---

  const renderHome = () => (
    <div className="min-h-screen flex flex-col items-center justify-center p-6 animate-in fade-in duration-500 relative overflow-hidden">
        {/* Decorative blobs */}
        <div className="absolute top-[-10%] left-[-10%] w-64 h-64 bg-pink-200 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob"></div>
        <div className="absolute top-[-10%] right-[-10%] w-64 h-64 bg-[#ffa9c2] rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-2000"></div>
        <div className="absolute bottom-[-20%] left-[20%] w-80 h-80 bg-purple-200 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-4000"></div>

        <div className="text-center mb-12 relative z-10">
            <div className="bg-white p-4 rounded-3xl shadow-xl shadow-pink-100 inline-block mb-6 transform -rotate-3 hover:rotate-0 transition-transform duration-300">
                 <Sparkles size={48} className="text-[#ff5c8d]" />
            </div>
            <h1 className="text-4xl md:text-5xl font-black text-stone-700 tracking-tight mb-4">
                百百嵂的委託小舖
            </h1>
            <p className="text-stone-400 text-lg font-medium">
                歡迎光臨！請選擇您需要的服務 🎨
            </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full max-w-2xl relative z-10">
            {/* Request Button */}
            <button 
                onClick={() => isCommissionsOpen && setCurrentPage('request')}
                disabled={!isCommissionsOpen}
                className={`group rounded-[2.5rem] p-8 text-left transition-all duration-300 
                    ${isCommissionsOpen 
                        ? 'bg-[#ffa9c2] hover:bg-[#ff94b3] text-white hover:-translate-y-2 hover:shadow-xl hover:shadow-pink-200 cursor-pointer' 
                        : 'bg-stone-200 text-stone-400 cursor-not-allowed border-4 border-stone-100'
                    }`}
            >
                <div className={`w-16 h-16 rounded-2xl flex items-center justify-center mb-6 transition-transform backdrop-blur-sm
                     ${isCommissionsOpen ? 'bg-white/20 text-white group-hover:scale-110' : 'bg-stone-300 text-stone-500'}
                `}>
                    {isCommissionsOpen ? <PenTool size={32} /> : <Ban size={32} />}
                </div>
                <h2 className="text-2xl font-bold mb-2">
                    {isCommissionsOpen ? '我要委託' : '暫停接單'}
                </h2>
                <p className={`font-medium ${isCommissionsOpen ? 'text-pink-100' : 'text-stone-400'}`}>
                    {isCommissionsOpen 
                        ? '喜歡我的畫風嗎？\n填寫表單送出您的委託需求！' 
                        : '目前排單已滿或休息中，\n請關注後續公告開啟時間。'
                    }
                </p>
            </button>

            {/* Tracking Button */}
            <button 
                onClick={() => setCurrentPage('tracking')}
                className="group bg-white hover:bg-stone-50 border-4 border-stone-100 hover:border-pink-200 rounded-[2.5rem] p-8 text-left transition-all duration-300 hover:-translate-y-2 hover:shadow-xl hover:shadow-pink-100"
            >
                <div className="bg-pink-50 w-16 h-16 rounded-2xl flex items-center justify-center text-[#ff5c8d] mb-6 group-hover:scale-110 transition-transform">
                    <Search size={32} />
                </div>
                <h2 className="text-2xl font-bold text-stone-700 mb-2">委託進度追蹤</h2>
                <p className="text-stone-400 font-medium">已經有委託了嗎？<br/>輸入 ID 查詢目前的繪製進度。</p>
            </button>
        </div>

        <div className="mt-12 flex flex-col items-center gap-4 relative z-10">
            <div className="text-stone-300 text-sm font-bold">
                © 2026 CommissionTrack
            </div>

            <button 
                onClick={handleModeSwitchRequest}
                className={`p-2 rounded-full transition-all duration-300 ${viewMode === 'admin' ? 'bg-stone-200 text-stone-600 hover:bg-stone-300' : 'text-stone-300 hover:text-stone-400 hover:bg-pink-50'}`}
                title={viewMode === 'client' ? "管理員登入" : "登出管理模式"}
            >
                {viewMode === 'admin' ? <Unlock size={16} /> : <Lock size={16} />}
            </button>
        </div>
    </div>
  );

  const renderRequest = () => (
      <div className="min-h-screen pt-8 pb-10 px-4">
          <div className="max-w-3xl mx-auto mb-6">
              <button 
                onClick={() => setCurrentPage('home')}
                className="flex items-center gap-2 text-stone-400 hover:text-stone-600 font-bold bg-white px-4 py-2 rounded-full shadow-sm hover:shadow-md transition-all"
              >
                  <Home size={18} /> 返回首頁
              </button>
          </div>
          <ClientRequestForm 
            availableTypes={commissionTypes}
            onSubmit={handleClientRequestSubmit}
            onCancel={() => setCurrentPage('home')}
          />
      </div>
  );

  const renderTracking = () => (
    <div className="min-h-screen flex flex-col relative">
      {/* Top Header */}
      <div className="pt-8 px-6 max-w-5xl mx-auto w-full">
         <div className="flex items-center justify-between mb-8 text-[#ff5c8d] opacity-90">
            <div className="flex items-center gap-3">
                 <button 
                    onClick={() => setCurrentPage('home')}
                    className="bg-white p-2 rounded-full shadow-sm text-stone-400 hover:text-[#ff5c8d] transition-colors"
                  >
                      <Home size={20} />
                  </button>
                <h1 className="text-xl font-bold tracking-wide">委託進度管理</h1>
            </div>

            {viewMode === 'admin' && (
                <div className="flex items-center gap-3">
                     {/* Commission Toggle Switch */}
                     <button
                        onClick={toggleCommissionStatus}
                        className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold border transition-all
                            ${isCommissionsOpen 
                                ? 'bg-green-100 text-green-600 border-green-200 hover:bg-green-200' 
                                : 'bg-stone-200 text-stone-500 border-stone-300 hover:bg-stone-300'
                            }`}
                        title={isCommissionsOpen ? "目前開放中 (點擊關閉)" : "目前關閉中 (點擊開放)"}
                     >
                        <Power size={14} />
                        {isCommissionsOpen ? '接單中' : '暫停中'}
                     </button>

                    <span className="text-sm font-bold bg-white px-3 py-1.5 rounded-full border border-stone-200 shadow-sm text-stone-600 animate-in fade-in flex items-center gap-2">
                        <LayoutDashboard size={14}/> 管理員模式
                    </span>
                </div>
            )}
        </div>

        {/* Intro / Stats */}
        <div className="mb-10 text-center sm:text-left sm:flex justify-between items-end animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="mb-8 sm:mb-0">
                <h2 className="text-3xl font-bold text-[#ff5c8d] mb-3 tracking-tight">
                    {viewMode === 'client' 
                        ? '委託進度查詢 ✨' 
                        : `歡迎回來，${ARTIST_NAME}！🎨`
                    }
                </h2>
                <p className="text-stone-500 max-w-lg font-medium leading-relaxed">
                    {viewMode === 'client' 
                        ? '請輸入您的委託 ID 或名稱，查看目前的繪製進度。' 
                        : '今天也要元氣滿滿的畫圖！這裡可以管理排單和進度喔。'}
                </p>
            </div>
            <div className="flex gap-3 justify-center sm:justify-end text-sm flex-wrap">
                {viewMode === 'admin' && (
                    <div className="bg-[#fff0f5] border-2 border-[#ffa9c2] px-4 py-3 rounded-2xl text-center min-w-[80px] shadow-sm transform hover:-translate-y-1 transition-transform">
                        <div className="text-2xl font-bold text-[#ff5c8d] flex items-center justify-center gap-1">
                            <span className="text-lg">$</span>
                            {stats.total.toLocaleString()}
                        </div>
                        <div className="text-xs text-[#ff5c8d]/70 font-bold">預估本月收益</div>
                    </div>
                )}
                <div className="bg-white border-2 border-stone-200 px-4 py-3 rounded-2xl text-center min-w-[80px] shadow-sm transform hover:-translate-y-1 transition-transform">
                    <div className="text-2xl font-bold text-stone-600">{stats.queue}</div>
                    <div className="text-xs text-stone-400 font-bold">排單中</div>
                </div>
                <div className="bg-white border-2 border-pink-100 px-4 py-3 rounded-2xl text-center min-w-[80px] shadow-sm transform hover:-translate-y-1 transition-transform">
                    <div className="text-2xl font-bold text-[#ff5c8d]">{stats.active}</div>
                    <div className="text-xs text-pink-400 font-bold">繪製中</div>
                </div>
                <div className="bg-white border-2 border-[#ffa9c2]/20 px-4 py-3 rounded-2xl text-center min-w-[80px] shadow-sm transform hover:-translate-y-1 transition-transform">
                    <div className="text-2xl font-bold text-[#ffa9c2]">{stats.done}</div>
                    <div className="text-xs text-[#ffa9c2]/70 font-bold">已完成</div>
                </div>
            </div>
        </div>

        {/* Controls - Floating & Rounded */}
        <div className="flex flex-col md:flex-row gap-4 mb-10 sticky top-6 z-40 bg-[#fffafb]/90 p-4 -mx-4 md:mx-0 rounded-3xl border-2 border-white shadow-lg shadow-pink-100/50 backdrop-blur-md animate-in fade-in slide-in-from-bottom-4">
            <div className="relative flex-grow">
            <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-stone-400" size={20} />
            <input 
                type="text" 
                placeholder={viewMode === 'client' ? "輸入您的名稱 (ID) 查詢進度..." : "搜尋委託..."}
                className="w-full bg-white border-2 border-stone-200 text-stone-700 pl-12 pr-6 py-3 rounded-full focus:ring-4 focus:ring-[#ffa9c2]/10 focus:border-[#ffa9c2] focus:outline-none transition-all placeholder:text-stone-400 font-medium"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
            />
            </div>

            <div className="flex gap-3 overflow-x-auto pb-2 md:pb-0 hide-scrollbar px-1">
            <select 
                className="bg-white border-2 border-stone-200 text-stone-600 px-6 py-3 rounded-full focus:ring-4 focus:ring-[#ffa9c2]/10 focus:border-[#ffa9c2] focus:outline-none font-bold cursor-pointer hover:border-stone-300"
                value={statusFilter}
                onChange={(e) => setStatusFilter(e.target.value as any)}
            >
                <option value="All">所有狀態</option>
                {Object.values(CommissionStatus).map(s => (
                    <option key={s} value={s}>{s}</option>
                ))}
            </select>

            {viewMode === 'admin' && (
                <button 
                    onClick={() => setIsAdding(!isAdding)}
                    className="flex items-center gap-2 bg-[#ffa9c2] hover:bg-[#ff94b3] text-white px-6 py-3 rounded-full font-bold transition-all shadow-lg shadow-pink-200 hover:shadow-xl hover:-translate-y-0.5 whitespace-nowrap active:scale-95"
                >
                    <Palette size={20} /> 新增委託
                </button>
            )}
            </div>
        </div>

        {/* Add Form (Admin Only) */}
        {viewMode === 'admin' && isAdding && (
            <AddCommissionForm 
                onAdd={handleAdd} 
                onCancel={() => setIsAdding(false)} 
                availableTypes={commissionTypes}
                onManageTypes={() => setShowTypeManager(true)}
            />
        )}

        {/* List */}
        <div className="space-y-6 pb-20">
            {!shouldShowList ? (
                // Client Mode: No Search Yet
                <div className="text-center py-20 opacity-70">
                    <div className="mx-auto w-20 h-20 bg-pink-50 rounded-full flex items-center justify-center mb-5 animate-[pulse_3s_ease-in-out_infinite]">
                        <Search className="text-pink-200" size={36} />
                    </div>
                    <h3 className="text-xl font-bold text-stone-500">輸入委託人名稱開始查詢</h3>
                    <p className="text-stone-400 mt-2 font-medium text-sm">請在上方搜尋欄輸入您的 ID 以查看進度</p>
                </div>
            ) : filteredCommissions.length === 0 ? (
                // Search resulted in empty
                <div className="text-center py-24 bg-white rounded-3xl border-2 border-dashed border-stone-200">
                    <div className="mx-auto w-20 h-20 bg-stone-100 rounded-full flex items-center justify-center mb-4">
                        <Search className="text-stone-400" size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-stone-600">找不到相關委託捏...</h3>
                    <p className="text-stone-400 mt-2 font-medium">
                        {viewMode === 'admin' ? "目前沒有符合條件的委託" : "試試看別的關鍵字？"}
                    </p>
                </div>
            ) : (
                // Results List
                filteredCommissions.map(commission => (
                    <CommissionCard 
                        key={commission.id}
                        commission={commission}
                        isAdmin={viewMode === 'admin'}
                        onUpdateStatus={handleUpdateStatus}
                        onDelete={handleDelete}
                        onEdit={(c) => setEditingCommission(c)}
                    />
                ))
            )}
        </div>
      </div>

      {/* Footer with Admin Switch */}
      <footer className="py-8 border-t border-stone-200 text-center mt-auto">
        <p className="text-stone-400 text-sm font-medium mb-4">
            © 2026 CommissionTrack
        </p>

        <div className="flex justify-center">
            <button 
                onClick={handleModeSwitchRequest}
                className={`p-2 rounded-full transition-all duration-300 ${viewMode === 'admin' ? 'bg-stone-200 text-stone-600 hover:bg-stone-300' : 'text-stone-300 hover:text-stone-400 hover:bg-stone-100'}`}
                title={viewMode === 'client' ? "管理員登入" : "登出管理模式"}
            >
                {viewMode === 'admin' ? <Unlock size={16} /> : <Lock size={16} />}
            </button>
        </div>
      </footer>
    </div>
  );

  return (
    <div className="bg-[#fffafb] min-h-screen font-sans text-stone-600 selection:bg-pink-100 selection:text-pink-500">
      {currentPage === 'home' && renderHome()}
      {currentPage === 'request' && renderRequest()}
      {currentPage === 'tracking' && renderTracking()}

      {/* Auth Modal */}
      {showAuthModal && (
        <div className="fixed inset-0 bg-stone-900/40 backdrop-blur-sm z-[70] flex items-center justify-center p-4 animate-in fade-in duration-200">
            <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl border-2 border-pink-100 animate-in zoom-in-95 duration-200 relative overflow-hidden">
                <button 
                    onClick={() => setShowAuthModal(false)} 
                    className="absolute top-4 right-4 text-stone-300 hover:text-stone-500 transition-colors"
                >
                    <X size={20} />
                </button>

                <div className="text-center mb-6">
                    <div className="w-16 h-16 bg-pink-50 text-[#ff5c8d] rounded-2xl flex items-center justify-center mx-auto mb-4">
                        <Lock size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-stone-700">管理員登入</h3>
                    <p className="text-stone-400 text-sm mt-1">請輸入通行密碼以進入管理模式</p>
                </div>

                <form onSubmit={handleAuthSubmit} className="space-y-4">
                    <div className="relative">
                        <Key className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
                        <input 
                            ref={passwordInputRef}
                            type="password" 
                            id="password-input"
                            className={`w-full bg-stone-50 border-2 ${authError ? 'border-red-300 bg-red-50' : 'border-stone-200'} rounded-2xl pl-11 pr-4 py-3 text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-bold transition-all placeholder:text-stone-300`}
                            placeholder="Password"
                            value={passwordInput}
                            onChange={(e) => {
                                setPasswordInput(e.target.value);
                                setAuthError(false);
                            }}
                        />
                    </div>
                    {authError && (
                        <p className="text-xs text-red-400 font-bold text-center animate-in slide-in-from-top-1">
                            密碼錯誤，請再試一次。
                        </p>
                    )}
                    <button 
                        type="submit"
                        className="w-full bg-[#ffa9c2] hover:bg-[#ff94b3] text-white font-bold py-3 rounded-2xl transition-all shadow-lg shadow-pink-200 hover:-translate-y-0.5 active:scale-95 flex items-center justify-center gap-2"
                    >
                        確認登入 <ChevronRight size={16} />
                    </button>
                </form>
            </div>
        </div>
      )}

      {/* Modals */}
      {viewMode === 'admin' && showTypeManager && (
          <TypeManager 
            types={commissionTypes}
            onUpdateTypes={setCommissionTypes}
            onClose={() => setShowTypeManager(false)}
          />
      )}

      {viewMode === 'admin' && editingCommission && (
        <EditCommissionForm 
            commission={editingCommission}
            onSave={handleEdit}
            onCancel={() => setEditingCommission(null)}
            availableTypes={commissionTypes}
            onManageTypes={() => setShowTypeManager(true)}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Commission, CommissionStatus, CommissionType } from '../types';
import { Send, X, Link as LinkIcon, Upload, Trash2, Sparkles, CheckCircle, Calculator, FileText } from 'lucide-react';

interface ClientRequestFormProps {
  onSubmit: (c: Commission) => void;
  onCancel: () => void;
  availableTypes: CommissionType[];
}

export const ClientRequestForm: React.FC<ClientRequestFormProps> = ({ onSubmit, onCancel, availableTypes }) => {
  const defaultTypeName = availableTypes.length > 0 ? availableTypes[0].name : '';
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [generatedId, setGeneratedId] = useState('');
  const [agreedToTerms, setAgreedToTerms] = useState(false);

  const [formData, setFormData] = useState<Partial<Commission>>({
    clientName: '',
    title: '',
    description: '',
    type: defaultTypeName,
    thumbnailUrl: ''
  });

  // Find price based on selected type
  const estimatedPrice = useMemo(() => {
    const typeObj = availableTypes.find(t => t.name === formData.type);
    return typeObj ? typeObj.price : 0;
  }, [formData.type, availableTypes]);

  useEffect(() => {
    if (availableTypes.length > 0 && (!formData.type || !availableTypes.some(t => t.name === formData.type))) {
        setFormData(prev => ({ ...prev, type: availableTypes[0].name }));
    }
  }, [availableTypes, formData.type]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        if (file.size > 800 * 1024) {
            alert("圖片檔案過大 (超過 800KB)。建議使用外部連結。");
            return;
        }
        const reader = new FileReader();
        reader.onloadend = () => {
            setFormData(prev => ({ ...prev, thumbnailUrl: reader.result as string }));
        };
        reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!agreedToTerms) {
        alert("請先閱讀並同意委託須知。");
        return;
    }

    const newId = `c-${Date.now().toString().slice(-6)}`; // Simple shorter ID
    setGeneratedId(newId);

    const newCommission: Commission = {
      id: newId,
      artistId: '',
      clientName: formData.clientName || '匿名',
      title: formData.title || '未命名委託',
      description: formData.description || '',
      type: formData.type || '其他',
      price: estimatedPrice, // Set the estimated price as initial price
      status: CommissionStatus.QUEUE,
      dateAdded: new Date().toISOString().split('T')[0],
      lastUpdated: new Date().toISOString().split('T')[0],
      thumbnailUrl: formData.thumbnailUrl || ''
    };

    onSubmit(newCommission);
    setIsSubmitted(true);
  };

  if (isSubmitted) {
      return (
          <div className="bg-white border-2 border-[#ffa9c2] rounded-3xl p-10 max-w-lg mx-auto text-center shadow-xl animate-in zoom-in-95">
              <div className="w-20 h-20 bg-green-100 text-green-500 rounded-full flex items-center justify-center mx-auto mb-6">
                  <CheckCircle size={40} />
              </div>
              <h3 className="text-2xl font-bold text-stone-700 mb-2">委託申請已送出！</h3>
              <p className="text-stone-500 mb-6">感謝您的委託，繪師將會盡快確認您的需求。</p>

              <div className="bg-stone-50 border-2 border-dashed border-stone-200 rounded-2xl p-6 mb-8">
                  <p className="text-xs font-bold text-stone-400 mb-2">您的追蹤 ID (請妥善保存)</p>
                  <p className="text-3xl font-black text-[#ff5c8d] tracking-wider select-all cursor-text">{generatedId}</p>
              </div>

              <div className="bg-pink-50 rounded-xl p-4 mb-8">
                  <p className="text-stone-500 text-sm font-bold">總金額</p>
                  <p className="text-2xl font-black text-[#ff5c8d]">
                    {typeof estimatedPrice === 'number' ? `NT$ ${estimatedPrice}` : estimatedPrice}
                  </p>
                  <p className="text-xs text-stone-400 mt-1">* 實際金額可能會依複雜度調整</p>
              </div>

              <button 
                onClick={onCancel}
                className="bg-[#ffa9c2] hover:bg-[#ff94b3] text-white font-bold py-3 px-10 rounded-full transition-all shadow-lg shadow-pink-200 hover:-translate-y-1"
              >
                  返回首頁
              </button>
          </div>
      );
  }

  return (
    <div className="bg-white border-2 border-pink-100 rounded-3xl p-8 shadow-xl shadow-pink-50/50 max-w-3xl mx-auto animate-in fade-in slide-in-from-bottom-4">
      <div className="flex justify-between items-center mb-8 pb-4 border-b-2 border-stone-100">
        <h3 className="text-xl font-bold text-[#ff5c8d] flex items-center gap-3">
            <div className="bg-pink-100 p-2 rounded-xl text-[#ff5c8d]">
                <Sparkles size={24} /> 
            </div>
            填寫委託單
        </h3>
        <button onClick={onCancel} className="bg-stone-100 p-2 rounded-full text-stone-400 hover:text-stone-600 hover:bg-stone-200 transition-colors">
            <X size={20} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-8">
        <div className="space-y-5 md:col-span-1">
          <div>
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">您的暱稱 / 稱呼</label>
            <input 
              required
              type="text" 
              className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium transition-all"
              value={formData.clientName}
              onChange={e => setFormData({...formData, clientName: e.target.value})}
              placeholder="例如: 糰子"
            />
          </div>
          <div>
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">委託標題 (角色/主題)</label>
            <input 
              required
              type="text" 
              className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium transition-all"
              value={formData.title}
              onChange={e => setFormData({...formData, title: e.target.value})}
              placeholder="例如: 原創角色立繪"
            />
          </div>
           <div>
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">想要的委託項目</label>
            <div className="relative">
                <select 
                className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium appearance-none cursor-pointer transition-all"
                value={formData.type}
                onChange={e => setFormData({...formData, type: e.target.value as any})}
                >
                    {availableTypes.map(t => (
                        <option key={t.name} value={t.name}>
                          {t.name} ({typeof t.price === 'number' ? `NT$ ${t.price}` : t.price})
                        </option>
                    ))}
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-stone-400">
                    ▼
                </div>
            </div>
          </div>
        </div>

        <div className="space-y-5 md:col-span-1">
          {/* Image Upload Section */}
          <div>
             <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">參考圖片 (角色設定/構圖參考)</label>

             {formData.thumbnailUrl ? (
                 <div className="relative group w-full h-32 rounded-2xl overflow-hidden border-2 border-pink-100 bg-pink-50">
                    <img src={formData.thumbnailUrl} alt="Preview" className="w-full h-full object-cover" />
                    <button 
                        type="button"
                        onClick={() => setFormData({...formData, thumbnailUrl: ''})}
                        className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-md"
                    >
                        <Trash2 size={16} />
                    </button>
                 </div>
             ) : (
                <div className="space-y-2">
                    {/* Upload Box */}
                    <div 
                        onClick={() => fileInputRef.current?.click()}
                        className="w-full h-20 border-2 border-dashed border-pink-200 rounded-2xl flex flex-col items-center justify-center text-pink-300 hover:text-pink-400 hover:border-pink-300 hover:bg-pink-50 transition-all cursor-pointer gap-1"
                    >
                        <Upload size={20} />
                        <span className="text-xs font-bold">點擊上傳 (Max 800KB)</span>
                        <input 
                            ref={fileInputRef}
                            type="file" 
                            accept="image/*" 
                            className="hidden" 
                            onChange={handleFileChange}
                        />
                    </div>

                    {/* URL Input Fallback */}
                    <div className="relative">
                        <input 
                            type="url" 
                            className="w-full bg-stone-50 border-2 border-stone-200 rounded-xl pl-9 pr-4 py-2 text-xs text-stone-700 focus:ring-4 focus:ring-[#ffa9c2]/20 focus:border-[#ffa9c2] focus:outline-none font-medium transition-all placeholder:text-stone-400"
                            value={formData.thumbnailUrl}
                            onChange={e => setFormData({...formData, thumbnailUrl: e.target.value})}
                            placeholder="或是貼上圖片連結..."
                        />
                        <LinkIcon size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400" />
                    </div>
                </div>
             )}
          </div>

          {/* Price Estimate Display */}
          <div className="bg-stone-50 border-2 border-stone-200 rounded-2xl p-4 flex items-center justify-between">
             <div className="flex items-center gap-2 text-stone-500 font-bold text-sm">
                 <Calculator size={18} /> 總金額
             </div>
             <div className="text-xl font-black text-[#ff5c8d]">
                 {typeof estimatedPrice === 'number' ? `NT$ ${estimatedPrice}` : estimatedPrice}
             </div>
          </div>
        </div>

        <div className="md:col-span-2">
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">詳細需求描述</label>
