    const unsubscribeCommissions = subscribeToCommissions((data) => {
      setCommissions(data);
      setIsLoaded(true);
    });

    // 2. Subscribe to Settings (Types & Open Status)
    const unsubscribeSettings = subscribeToSettings((settings) => {
      if (settings) {
        setIsCommissionsOpen(settings.isOpen);
