/**
 * 圖片壓縮與上傳
 * 自動將圖片壓縮至最大邊長 1200px，品質 0.7 (JPEG)
 * 加入 8 秒超時機制，超時直接轉 Base64
 */
export const uploadCommissionImage = async (file: File): Promise<string> => {
    // 壓縮 helper
    const compressImage = (sourceFile: File): Promise<Blob> => {
        return new Promise((resolve, reject) => {
            const img = new Image();
            const reader = new FileReader();

            reader.onload = (e) => { img.src = e.target?.result as string; };
            reader.onerror = () => reject(new Error("FileReader failed"));

            // 加入 FileReader 的安全超時 (防止壞檔讀取卡死)
            setTimeout(() => reject(new Error("Image read timeout")), 3000);

            img.onload = () => {
                const canvas = document.createElement('canvas');
                let width = img.width;
                let height = img.height;
                const MAX_SIZE = 1200;

                if (width > height) {
                    if (width > MAX_SIZE) { height *= MAX_SIZE / width; width = MAX_SIZE; }
                } else {
                    if (height > MAX_SIZE) { width *= MAX_SIZE / height; height = MAX_SIZE; }
                }

                canvas.width = width;
                canvas.height = height;
                const ctx = canvas.getContext('2d');
                if (!ctx) { reject(new Error("Canvas Context Error")); return; }

                ctx.drawImage(img, 0, 0, width, height);

                canvas.toBlob((blob) => {
                    if (blob) resolve(blob);
                    else reject(new Error("Compression Failed"));
                }, 'image/jpeg', 0.7);
            };
            img.onerror = () => reject(new Error("Image load failed"));
        });
    };

    const blobToBase64 = (blob: Blob): Promise<string> => {
        return new Promise((resolve) => {
            const reader = new FileReader();
            reader.onloadend = () => resolve(reader.result as string);
            reader.readAsDataURL(blob);
        });
    };

    try {
        // 1. 壓縮
        let blobToUpload: Blob;
        try {
            // 壓縮也限制時間，避免某些奇怪圖片卡死 CPU
            blobToUpload = await withTimeout(compressImage(file), 4000, "Compression timeout");
            console.log(`Compressed: ${(blobToUpload.size / 1024).toFixed(2)} KB`);
        } catch (e) {
            console.warn("Compression failed/timed out, using original:", e);
            blobToUpload = file;
        }

        // 2. 上傳 (如果 storage 存在)
        if (storage) {
            try {
                const fileName = `commission_images/${Date.now()}_img.jpg`;
                const storageRef = ref(storage, fileName);

                // 強制上傳必須在 5 秒內完成，否則視為失敗 (轉用 LocalStorage)
                const uploadTask = uploadBytes(storageRef, blobToUpload);
                const snapshot = await withTimeout(uploadTask, 5000, "Storage upload timeout");

                const downloadURL = await getDownloadURL(snapshot.ref);
                return downloadURL;
            } catch (error) {
                console.error("☁️ Storage 上傳超時或失敗，轉為 Base64 本地儲存");
                return await blobToBase64(blobToUpload);
            }
        } else {
            return await blobToBase64(blobToUpload);
        }
    } catch (e) {
        console.error("Critical Image Error:", e);
        // 最後一道防線：回傳原始檔案 Base64，絕不拋出錯誤導致 UI 卡死
        try {
            return await blobToBase64(file);
        } catch {
            return "";
        }
    }
};

