        {viewMode === 'admin' && editingCommission && (
            <EditCommissionForm 
                commission={editingCommission} 
                onSave={handleEdit} 
                onCancel={() => setEditingCommission(null)} 
                availableTypes={commissionTypes}
                onManageTypes={() => setShowTypeManager(true)}
