                            <option key={t.name} value={t.name}>{t.name}</option>
                        ))}
                    </select>
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-stone-400">
                        ▼
                    </div>
                </div>
                <button 
                    type="button" 
                    onClick={onManageTypes}
